/** @file*/

#include "internal_nn_math.h"

//// Relu Functions

void riscv_nn_relu_s8(q7_t * in_out, uint32_t size)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
    unsigned long dlen_ratio = NDS_VEC_CSR_GET_DLEN_RATIO();
    long vl, maxvl_perf_vg;
    long size2 = size;
    if (dlen_ratio == NDS_MVEC_CFG_DW_VAL_1_1)
    {
        maxvl_perf_vg = __riscv_vsetvlmax_e8m8();
        long maxvl_per_loop = maxvl_perf_vg << 2;
        while (size2 >= maxvl_per_loop)
        {
            q7_t * in_out2 = in_out + maxvl_perf_vg;
            vint8m8_t vIn_out = __riscv_vle8_v_i8m8(in_out, maxvl_perf_vg);
            q7_t * in_out3 = in_out2 + maxvl_perf_vg;
            vint8m8_t vIn_out2 = __riscv_vle8_v_i8m8(in_out2, maxvl_perf_vg);
            q7_t * in_out4 = in_out3 + maxvl_perf_vg;
            vint8m8_t vIn_out3 = __riscv_vle8_v_i8m8(in_out3, maxvl_perf_vg);
            vint8m8_t vIn_out4 = __riscv_vle8_v_i8m8(in_out4, maxvl_perf_vg);
            vIn_out = __riscv_vmax(vIn_out, 0, maxvl_perf_vg);
            vIn_out2 = __riscv_vmax(vIn_out2, 0, maxvl_perf_vg);
            vIn_out3 = __riscv_vmax(vIn_out3, 0, maxvl_perf_vg);
            vIn_out4 = __riscv_vmax(vIn_out4, 0, maxvl_perf_vg);
            __riscv_vse8(in_out, vIn_out, maxvl_perf_vg);
            in_out += maxvl_per_loop;
            __riscv_vse8(in_out2, vIn_out2, maxvl_perf_vg);
            size2 -= maxvl_per_loop;
            __riscv_vse8(in_out3, vIn_out3, maxvl_perf_vg);
            __riscv_vse8(in_out4, vIn_out4, maxvl_perf_vg);
        }

        while (size2 > 0)
        {
            vl = __riscv_vsetvl_e8m8(size2);
            vint8m8_t vIn_out = __riscv_vle8_v_i8m8(in_out, vl);
            size2 -= vl;
            vIn_out = __riscv_vmax(vIn_out, 0, vl);
            __riscv_vse8(in_out, vIn_out, vl);
            in_out += vl;
        }
    }
    else
    {
        maxvl_perf_vg = __riscv_vsetvlmax_e8m4();
        long maxvl_per_loop = maxvl_perf_vg << 2;
        while (size2 >= maxvl_per_loop)
        {
            q7_t * in_out2 = in_out + maxvl_perf_vg;
            vint8m4_t vIn_out = __riscv_vle8_v_i8m4(in_out, maxvl_perf_vg);
            q7_t * in_out3 = in_out2 + maxvl_perf_vg;
            vint8m4_t vIn_out2 = __riscv_vle8_v_i8m4(in_out2, maxvl_perf_vg);
            q7_t * in_out4 = in_out3 + maxvl_perf_vg;
            vint8m4_t vIn_out3 = __riscv_vle8_v_i8m4(in_out3, maxvl_perf_vg);
            vint8m4_t vIn_out4 = __riscv_vle8_v_i8m4(in_out4, maxvl_perf_vg);
            vIn_out = __riscv_vmax(vIn_out, 0, maxvl_perf_vg);
            vIn_out2 = __riscv_vmax(vIn_out2, 0, maxvl_perf_vg);
            vIn_out3 = __riscv_vmax(vIn_out3, 0, maxvl_perf_vg);
            vIn_out4 = __riscv_vmax(vIn_out4, 0, maxvl_perf_vg);
            __riscv_vse8(in_out, vIn_out, maxvl_perf_vg);
            in_out += maxvl_per_loop;
            __riscv_vse8(in_out2, vIn_out2, maxvl_perf_vg);
            size2 -= maxvl_per_loop;
            __riscv_vse8(in_out3, vIn_out3, maxvl_perf_vg);
            __riscv_vse8(in_out4, vIn_out4, maxvl_perf_vg);
        }

        while (size2 > 0)
        {
            vl = __riscv_vsetvl_e8m4(size2);
            vint8m4_t vIn_out = __riscv_vle8_v_i8m4(in_out, vl);
            size2 -= vl;
            vIn_out = __riscv_vmax(vIn_out, 0, vl);
            __riscv_vse8(in_out, vIn_out, vl);
            in_out += vl;
        }
    }
#elif defined(ENA_VEC_ISA)
    unsigned long dlen_ratio = NDS_VEC_CSR_GET_DLEN_RATIO();
    unsigned long my_vtype;
    if (dlen_ratio == NDS_MVEC_CFG_DW_VAL_1_1)
    {
        my_vtype = NDS_VEC_MAKE_VTYPE(NDS_VEC_VTYPE_SEW_VAL_E8, NDS_VEC_VTYPE_LMUL_VAL_M8);
    }
    else
    {
        my_vtype = NDS_VEC_MAKE_VTYPE(NDS_VEC_VTYPE_SEW_VAL_E8, NDS_VEC_VTYPE_LMUL_VAL_M4);
    }

    long vl, maxvl_perf_vg;
    long size2 = size;

    NDS_VEC_VSETVL(maxvl_perf_vg, reg_x0, my_vtype);
    long maxvl_per_loop = maxvl_perf_vg << 2;
    while (size2 >= maxvl_per_loop)
    {
        q7_t * in_out2 = in_out  + maxvl_perf_vg;
        NDS_VEC_VLE8_V(NDS_VEC_V0, in_out);
        q7_t * in_out3 = in_out2 + maxvl_perf_vg;
        NDS_VEC_VLE8_V(NDS_VEC_V8, in_out2);
        q7_t * in_out4 = in_out3 + maxvl_perf_vg;
        NDS_VEC_VLE8_V(NDS_VEC_V16, in_out3);
        NDS_VEC_VLE8_V(NDS_VEC_V24, in_out4);
        NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
        NDS_VEC_VMAX_VX(NDS_VEC_V8, NDS_VEC_V8, 0);
        NDS_VEC_VMAX_VX(NDS_VEC_V16, NDS_VEC_V16, 0);
        NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, 0);
        NDS_VEC_VSE8_V(NDS_VEC_V0, in_out);
        in_out += maxvl_per_loop;
        NDS_VEC_VSE8_V(NDS_VEC_V8, in_out2);
        size2 -= maxvl_per_loop;
        NDS_VEC_VSE8_V(NDS_VEC_V16, in_out3);
        NDS_VEC_VSE8_V(NDS_VEC_V24, in_out4);
    }

    while (size2 > 0)
    {
        NDS_VEC_VSETVL(vl, size2, my_vtype);
        NDS_VEC_VLE8_V(NDS_VEC_V0, in_out);
        size2 -= vl;
        NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
        NDS_VEC_VSE8_V(NDS_VEC_V0, in_out);
        in_out += vl;
    }
#elif defined(ENA_DSP_ISA)
    long_t cst_zero = 0L;

    while (size >= (SIMD_NUM_Q7*2))
    {
        suni_t in_q7_1 = simd_load_8(in_out, 0);
        in_q7_1.l0 = NDS_DSP_SMAX8(in_q7_1.l0, cst_zero);
        simd_save_8(in_out, in_q7_1.l0);
        in_out += SIMD_NUM_Q7;
        size -= SIMD_NUM_Q7;

        suni_t in_q7_2 = simd_load_8(in_out, 0);
        in_q7_2.l0 = NDS_DSP_SMAX8(in_q7_2.l0, cst_zero);
        simd_save_8(in_out, in_q7_2.l0);
        in_out += SIMD_NUM_Q7;
        size -= SIMD_NUM_Q7;
    }

    while (size > 0)
    {
        *in_out = NDS_DSP_CLIP(*in_out, 8);
        in_out++;
        size--;
    }
#else
    uint32_t  i;

    for (i = 0; i < size; i++)
    {
        if (in_out[i] < 0)
            in_out[i] = 0;
    }

#endif

}

