255→
256→        NDS_VEC_VSE32_V(NDS_VEC_V8, out_vec);
257→        size -= vl;
258→        in_vec += vl;
259→        out_vec += vl;
260→    }
261→#endif
262→#else
263→    long i;
264→    for(i=0; i<size; i++)
