/** @file*/

#include "internal_nn_math.h"

//// Activation Functions

#ifdef ENA_VEC_ISA
// following macro is for v-ext algorithm (if following macro is defined, vfdiv
// will be replaced by vfrec7)
// #define ENA_FAST_ALGO
#endif

#ifndef ENA_EMPTY_FUN
//--- const values for tanh_f32 ---
static const float32_t tanh_f32_max = TANH_F32_MAX;
static const float32_t tanh_f32_min = TANH_F32_MIN;
static const float32_t tanh_thr     = TANH_F32_THR;
static const float32_t cst_1        = CST_1;
static const float32_t cst_2        = CST_2;
static const float32_t cst_1_3      = CST_1_3;



#if !(defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU))
extern float32_t exp_f32(float32_t x);
extern float32_t tanh_f32(float32_t x)
{
    float32_t ret;
    x = (x > tanh_f32_max)? tanh_f32_max : x;
    x = (x < tanh_f32_min)? tanh_f32_min : x;

    // x * (1 - x^2/3) if |x| < 5.e-3 or (exp2x - 1) / (exp2x + 1) otherwise
    if(fabs(x) < tanh_thr)
        ret = x * (1 - x*x*cst_1_3);
    else
        ret = (exp_f32(cst_2 * x) - cst_1) / (exp_f32(cst_2 * x) + cst_1);

    return ret;
}
#endif
#endif  //ENA_EMPTY_FUN

int32_t riscv_nn_tanh_f32(const float32_t * in_vec, uint32_t size, float32_t * out_vec)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#else
#if defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU) && !defined(ENA_ACE_RVV)
    //--- const values for taylor_poly_f32 ---
    // Exponent polynomial coefficients
    const float32_t exp_coe0 = EXP_COE0;
    const float32_t exp_coe1 = EXP_COE1;
    const float32_t exp_coe2 = EXP_COE2;
    const float32_t exp_coe3 = EXP_COE3;
    const float32_t exp_coe4 = EXP_COE4;
    const float32_t exp_coe5 = EXP_COE5;
    const float32_t exp_coe6 = EXP_COE6;
    const float32_t exp_coe7 = EXP_COE7;

    //--- const values for exp_f32 ---
    const float32_t ln2         = LN2;          // ln(2)
    const float32_t inv_ln2     = INV_LN2;      // 1/ln(2)
#endif

#if defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU) && defined(ENA_ACE_RVV)
    long vl;
    while(size > 0)
    {
        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec);

        //--- tanh_f32 begin ---
        NDS_VEC_VFMAX_VF(NDS_VEC_V0, NDS_VEC_V0, tanh_f32_min);
        NDS_VEC_VFMIN_VF(NDS_VEC_V0, NDS_VEC_V0, tanh_f32_max);

        // tanh's results (for those fabs(x) < CONST_THR)
        NDS_VEC_VMV_V_V(NDS_VEC_V8, NDS_VEC_V0);                    //copy of tanh input
        NDS_VEC_VFMUL_VV(NDS_VEC_V16, NDS_VEC_V0, NDS_VEC_V0);      //x^2
        NDS_VEC_VFMUL_VF(NDS_VEC_V24, NDS_VEC_V0, cst_1_3);         //x*cst_1_3
        NDS_VEC_VFNMSAC_VV(NDS_VEC_V8, NDS_VEC_V16, NDS_VEC_V24);   //x - x^3*cst_1_3

        NDS_VEC_VFMUL_VF(NDS_VEC_V16, NDS_VEC_V0, cst_2);           //cst_2 * x

        //--- exp_f32 begin ---
        ace_exp(NDS_VEC_V16, NDS_VEC_V16);
        //--- exp_f32 end ---

        //(exp2x - 1) / (exp2x + 1)
        NDS_VEC_VFSUB_VF(NDS_VEC_V24, NDS_VEC_V16, cst_1);
        NDS_VEC_VFADD_VF(NDS_VEC_V16, NDS_VEC_V16, cst_1);
#ifdef ENA_FAST_ALGO
        NDS_VEC_VFRECE7_V(NDS_VEC_V16, NDS_VEC_V16);
        NDS_VEC_VFMUL_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V16);
#else
        NDS_VEC_VFDIV_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V16);
#endif

        NDS_VEC_VFSGNJX_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V0);     //fabs(x)
        NDS_VEC_VMFGE_VF(NDS_VEC_V0, NDS_VEC_V0, tanh_thr);         //select those fabs(x) >= tanh_thr
        NDS_VEC_VMERGE_VVM(NDS_VEC_V24, NDS_VEC_V8, NDS_VEC_V24);
        //--- tanh_f32 end ---

        NDS_VEC_VSE32_V(NDS_VEC_V24, out_vec);
        size -= vl;
        in_vec += vl;
        out_vec += vl;
    }
#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU)
#ifdef ENA_VEC_INTRINSIC
    long vl;
    long size2 = size;
    while(size2 > 0)
    {
        vl = __riscv_vsetvl_e32m4(size2);
        vfloat32m4_t vin_vec = __riscv_vle32_v_f32m4(in_vec, vl);
        vin_vec = __riscv_vfmax(vin_vec, tanh_f32_min, vl);
        vin_vec = __riscv_vfmin(vin_vec, tanh_f32_max, vl);
        vin_vec = __riscv_vfmul(vin_vec, cst_2, vl);                           //cst_2 * x

        //--- exp_f32 begin ---
        // Perform range reduction [-log(2),log(2)]
        vfloat32m4_t vm = __riscv_vfmul(vin_vec, inv_ln2, vl);                 //x * inv_ln2;
        vint32m4_t vm_int = __riscv_vfcvt_rtz_x(vm, vl);                       //m (integer type)
        vm = __riscv_vfcvt_f(vm_int, vl);                                      //m (float type)
        vm = __riscv_vfnmsub(vm, ln2, vin_vec, vl);                            //val

        //--- taylor_poly_f32 begin ---
        vfloat32m4_t vaccumulator_a = __riscv_vfmv_v_f_f32m4(exp_coe0, vl);                   //A = exp_coe0
        vaccumulator_a = __riscv_vfmacc(vaccumulator_a, exp_coe4, vm, vl);                    //A = exp_coe0 + x * exp_coe4
        vfloat32m4_t vaccumulator_b = __riscv_vfmv_v_f_f32m4(exp_coe2, vl);                   //B = exp_coe2
        vaccumulator_b = __riscv_vfmacc(vaccumulator_b, exp_coe6, vm, vl);                    //B = exp_coe2 + x * exp_coe6
        vfloat32m4_t vaccumulator_c = __riscv_vfmv_v_f_f32m4(exp_coe1, vl);                   //C = exp_coe1
        vaccumulator_c = __riscv_vfmacc(vaccumulator_c, exp_coe5, vm, vl);                    //C = exp_coe1 + x * exp_coe5
        vfloat32m4_t vaccumulator_d = __riscv_vfmv_v_f_f32m4(exp_coe3, vl);                   //D = exp_coe3
        vaccumulator_d = __riscv_vfmacc(vaccumulator_d, exp_coe7, vm, vl);                    //D = exp_coe3 + x * exp_coe7
        vfloat32m4_t vz_float_pow2 = __riscv_vfmul(vm, vm, vl);                               //x2
        vm_int = __riscv_vsll(vm_int, 23, vl);                                                //m2
        vfloat32m4_t vz_float_pow4 = __riscv_vfmul(vz_float_pow2, vz_float_pow2, vl);         //x4
        vaccumulator_a = __riscv_vfmacc(vaccumulator_a, vaccumulator_b, vz_float_pow2, vl);   //A + B * x2
        vaccumulator_c = __riscv_vfmacc(vaccumulator_c, vaccumulator_d, vz_float_pow2, vl);   //C + D * x2
        vaccumulator_a = __riscv_vfmacc(vaccumulator_a, vaccumulator_c, vz_float_pow4, vl);   //(A + B * x2) + (C + D * x2) * x4
        //--- taylor_poly_f32 end ---

        // Reconstruct
        vint32m4_t vaccumulator_a_int = __riscv_vreinterpret_i32m4(vaccumulator_a);
        //--- exp_f32 end ---

        //(exp2x - 1) / (exp2x + 1)
        vaccumulator_a_int = __riscv_vsadd(vaccumulator_a_int, vm_int, vl);
        vaccumulator_a = __riscv_vreinterpret_f32m4(vaccumulator_a_int);
	vfloat32m4_t vin_tanh_vec = __riscv_vmv_v_v_f32m4(vin_vec, vl);                       //copy of tanh input
        vaccumulator_b = __riscv_vfmul(vin_vec, vin_vec, vl);                                 //x^2
        vaccumulator_c = __riscv_vfmul(vin_vec, cst_1_3, vl);                                 //x*cst_1_3
        vin_tanh_vec = __riscv_vfnmsac(vin_tanh_vec, vaccumulator_b, vaccumulator_c, vl);     //x - x^3*cst_1_3

        //(exp2x - 1) / (exp2x + 1)
        vfloat32m4_t vden = __riscv_vfadd(vaccumulator_a, cst_1, vl);
        vaccumulator_a = __riscv_vfsub(vaccumulator_a, cst_1, vl);
        #ifdef ENA_FAST_ALGO
            vden = __riscv_vfrec7(vden, vl);
            vaccumulator_a = __riscv_vfmul(vaccumulator_a, vden, vl);
        #else
            vaccumulator_a = __riscv_vfdiv(vaccumulator_a, vden, vl);
        #endif
        vin_vec = __riscv_vfsgnjx(vin_vec, vin_vec, vl);                                       //fabs(x)
        vbool8_t vtemp_mask = __riscv_vmfge(vin_vec, tanh_thr, vl);                            //select those fabs(x) >= tanh_thr
        vfloat32m4_t vresult_float = __riscv_vmerge_vvm_f32m4(vin_tanh_vec, vaccumulator_a, vtemp_mask, vl);

        __riscv_vse32(out_vec, vresult_float, vl);
        size2 -= vl;
        in_vec += vl;
        out_vec += vl;
    }
#else
    long vl;
    while(size > 0)
    {
        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec);

        //--- tanh_f32 begin ---
        NDS_VEC_VFMAX_VF(NDS_VEC_V0, NDS_VEC_V0, tanh_f32_min);
        NDS_VEC_VFMIN_VF(NDS_VEC_V0, NDS_VEC_V0, tanh_f32_max);

        NDS_VEC_VFMUL_VF(NDS_VEC_V4, NDS_VEC_V0, cst_2);            //cst_2 * x

        //--- exp_f32 begin ---
        // Perform range reduction [-log(2),log(2)]
        NDS_VEC_VFMUL_VF(NDS_VEC_V8, NDS_VEC_V4, inv_ln2);          //x * inv_ln2;
        NDS_VEC_VFCVT_RTZ_X_F_V(NDS_VEC_V8, NDS_VEC_V8);            //m (integer type)
        NDS_VEC_VFCVT_F_X_V(NDS_VEC_V12, NDS_VEC_V8);               //m (float type)
        NDS_VEC_VFNMSUB_VF(NDS_VEC_V12, ln2, NDS_VEC_V4);           //val

        //--- taylor_poly_exp_f32 begin ---
        NDS_VEC_VFMV_V_F(NDS_VEC_V16, exp_coe0);                    //A = exp_coe0
        NDS_VEC_VFMACC_VF(NDS_VEC_V16, exp_coe4, NDS_VEC_V12);      //A = exp_coe0 + x * exp_coe4
        NDS_VEC_VFMV_V_F(NDS_VEC_V20, exp_coe2);                    //B = exp_coe2
        NDS_VEC_VFMACC_VF(NDS_VEC_V20, exp_coe6, NDS_VEC_V12);      //B = exp_coe2 + x * exp_coe6
        NDS_VEC_VFMV_V_F(NDS_VEC_V24, exp_coe1);                    //C = exp_coe1
        NDS_VEC_VFMACC_VF(NDS_VEC_V24, exp_coe5, NDS_VEC_V12);      //C = exp_coe1 + x * exp_coe5
        NDS_VEC_VFMV_V_F(NDS_VEC_V28, exp_coe3);                    //D = exp_coe3
        NDS_VEC_VFMACC_VF(NDS_VEC_V28, exp_coe7, NDS_VEC_V12);      //D = exp_coe3 + x * exp_coe7
        NDS_VEC_VFMUL_VV(NDS_VEC_V12, NDS_VEC_V12, NDS_VEC_V12);    //x2
        NDS_VEC_VSLL_VX(NDS_VEC_V8, NDS_VEC_V8, 23);                //m2
        NDS_VEC_VFMACC_VV(NDS_VEC_V16, NDS_VEC_V20, NDS_VEC_V12);   //A + B * x2
        NDS_VEC_VFMACC_VV(NDS_VEC_V24, NDS_VEC_V28, NDS_VEC_V12);   //C + D * x2
        NDS_VEC_VFMUL_VV(NDS_VEC_V12, NDS_VEC_V12, NDS_VEC_V12);    //x4
        NDS_VEC_VFMACC_VV(NDS_VEC_V16, NDS_VEC_V24, NDS_VEC_V12);   //(A + B * x2) + (C + D * x2) * x4
        //--- taylor_poly_exp_f32 end ---

        // Reconstruct
        NDS_VEC_VSADD_VV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V8);
        //--- exp_f32 end ---

        // TODO: it's possible to remove vmv_v_v
        // tanh's results (for those fabs(x) < CONST_THR)
        NDS_VEC_VMV_V_V(NDS_VEC_V4, NDS_VEC_V0);                    //copy of tanh input
        NDS_VEC_VFMUL_VV(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V0);       //x^2
        NDS_VEC_VFMUL_VF(NDS_VEC_V12, NDS_VEC_V0, cst_1_3);         //x*cst_1_3
        NDS_VEC_VFNMSAC_VV(NDS_VEC_V4, NDS_VEC_V8, NDS_VEC_V12);    //x - x^3*cst_1_3

        //(exp2x - 1) / (exp2x + 1)
        NDS_VEC_VFSUB_VF(NDS_VEC_V8, NDS_VEC_V16, cst_1);
        NDS_VEC_VFADD_VF(NDS_VEC_V16, NDS_VEC_V16, cst_1);
#ifdef ENA_FAST_ALGO
        NDS_VEC_VFRECE7_V(NDS_VEC_V16, NDS_VEC_V16);
        NDS_VEC_VFMUL_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V16);
#else
        NDS_VEC_VFDIV_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V16);
#endif

        NDS_VEC_VFSGNJX_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V0);     //fabs(x)
        NDS_VEC_VMFGE_VF(NDS_VEC_V0, NDS_VEC_V0, tanh_thr);         //select those fabs(x) >= tanh_thr
        NDS_VEC_VMERGE_VVM(NDS_VEC_V8, NDS_VEC_V4, NDS_VEC_V8);
        //--- tanh_f32 end ---

        NDS_VEC_VSE32_V(NDS_VEC_V8, out_vec);
        size -= vl;
        in_vec += vl;
        out_vec += vl;
    }
#endif
#else
    long i;
    for(i=0; i<size; i++)
    {
        out_vec[i] = tanh_f32(in_vec[i]);
    }
#endif
#endif  // ENA_EMPTY_FUN
    return 0;
}

