/** @file*/

#include "internal_nn_math.h"

//// Softmax Functions

int32_t riscv_nn_softmax_f32(const float32_t * in_vec, uint32_t size, float32_t * out_vec)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#else
#if defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU) && !defined(ENA_ACE_RVV)
    //--- const values for taylor_poly_f32 ---
    // Exponent polynomial coefficients
    const float32_t exp_coe0 = EXP_COE0;
    const float32_t exp_coe1 = EXP_COE1;
    const float32_t exp_coe2 = EXP_COE2;
    const float32_t exp_coe3 = EXP_COE3;
    const float32_t exp_coe4 = EXP_COE4;
    const float32_t exp_coe5 = EXP_COE5;
    const float32_t exp_coe6 = EXP_COE6;
    const float32_t exp_coe7 = EXP_COE7;
    //--- const values for exp_f32 ---
    const float32_t ln2      = LN2;          // ln(2)
    const float32_t inv_ln2  = INV_LN2;      // 1/ln(2)
#endif

#if defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU) && defined(ENA_ACE_RVV)
    float32_t max, sum;
    float32_t *in_vec2, *out_vec2;
    long vl;
    long size2 = size;
    long ele_per_loop, ele_per_loop2;

    //find the maximun
    in_vec2 = (float32_t *)in_vec;
    NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
    NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec2);
    in_vec2 += vl;
    size2 -= vl;
    while(size2 > 0)
    {
        NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VLE32_V(NDS_VEC_V8, in_vec2);
        in_vec2 += vl;
        size2 -= vl;
        NDS_VEC_VFMAX_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);
    }
    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note teh avl here
    NDS_VEC_VFREDMAX_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V0);
    NDS_VEC_VFMV_F_S(max, NDS_VEC_V0);

    //calculate the exp and sum
    NDS_VEC_VSETVLI(ele_per_loop2, reg_x0, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
    ele_per_loop = ele_per_loop2 * 3;
    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
    NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);   //init sum
    in_vec2 = (float32_t *)in_vec;
    out_vec2 = out_vec;
    size2 = size;
    NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
    while(size2 >= ele_per_loop)
    {
        NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec2);
        in_vec2 += vl;
        NDS_VEC_VLE32_V(NDS_VEC_V8, in_vec2);
        in_vec2 += vl;
        NDS_VEC_VLE32_V(NDS_VEC_V16, in_vec2);
        in_vec2 += vl;
        NDS_VEC_VFSUB_VF(NDS_VEC_V0, NDS_VEC_V0, max);
        size2 -= ele_per_loop;
        NDS_VEC_VFSUB_VF(NDS_VEC_V8, NDS_VEC_V8, max);
        NDS_VEC_VFSUB_VF(NDS_VEC_V16, NDS_VEC_V16, max);

        //--- exp_f32 begin ---
        ace_exp(NDS_VEC_V0, NDS_VEC_V0);
        ace_exp(NDS_VEC_V8, NDS_VEC_V8);
        ace_exp(NDS_VEC_V16, NDS_VEC_V16);
        //--- exp_f32 end ---

        NDS_VEC_VFADD_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V0);     //accumulate sum_f32
        NDS_VEC_VFADD_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V8);     //accumulate sum_f32
        NDS_VEC_VFADD_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V16);    //accumulate sum_f32
        NDS_VEC_VSE32_V(NDS_VEC_V0, out_vec2);
        out_vec2 += vl;
        NDS_VEC_VSE32_V(NDS_VEC_V8, out_vec2);
        out_vec2 += vl;
        NDS_VEC_VSE32_V(NDS_VEC_V16, out_vec2);
        out_vec2 += vl;
    }
    while(size2 > 0)
    {
        NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec2);
        in_vec2 += vl;
        NDS_VEC_VFSUB_VF(NDS_VEC_V0, NDS_VEC_V0, max);
        size2 -= vl;

        //--- exp_f32 begin ---
        ace_exp(NDS_VEC_V0, NDS_VEC_V0);
        //--- exp_f32 end ---

        NDS_VEC_VFADD_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V0);     //accumulate sum_f32
        NDS_VEC_VSE32_V(NDS_VEC_V0, out_vec2);
        out_vec2 += vl;
    }
    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);   //for redsum
    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
    NDS_VEC_VFREDSUM_VS(NDS_VEC_V0, NDS_VEC_V24, NDS_VEC_V0);
#ifdef ENA_FAST_ALGO
    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VFRECE7_V(NDS_VEC_V0, NDS_VEC_V0);
#endif
    NDS_VEC_VFMV_F_S(sum, NDS_VEC_V0);

    //divide the output by sum
    ele_per_loop = ele_per_loop2 << 1;
    size2 = size;
    NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
    while (size2 >= ele_per_loop)
    {
        float32_t* out_vec2 = (float32_t*)out_vec + vl;
        NDS_VEC_VLE32_V(NDS_VEC_V0, out_vec);
        NDS_VEC_VLE32_V(NDS_VEC_V8, out_vec2);
#ifdef ENA_FAST_ALGO
        NDS_VEC_VFMUL_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
        NDS_VEC_VFMUL_VF(NDS_VEC_V8, NDS_VEC_V8, sum);
#else
        NDS_VEC_VFDIV_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
        NDS_VEC_VFDIV_VF(NDS_VEC_V8, NDS_VEC_V8, sum);
#endif
        NDS_VEC_VSE32_V(NDS_VEC_V0, out_vec);
        out_vec += ele_per_loop;
        NDS_VEC_VSE32_V(NDS_VEC_V8, out_vec2);
        size2 -= ele_per_loop;
    }
    while(size2 > 0)
    {
        NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VLE32_V(NDS_VEC_V0, out_vec);
#ifdef ENA_FAST_ALGO
        NDS_VEC_VFMUL_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
#else
        NDS_VEC_VFDIV_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
#endif
        NDS_VEC_VSE32_V(NDS_VEC_V0, out_vec);
        out_vec += vl;
        size2 -= vl;
    }
#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU)
    float32_t max, sum;
    float32_t *in_vec2, *out_vec2;
    long vl;
    long size2 = size;
    long ele_per_loop;
    const float32_t exp_max = EXP_F32_MAX;
    const float32_t exp_min = EXP_F32_MIN;

#ifdef ENA_VEC_INTRINSIC
    //find the maximun
    in_vec2 = (float32_t *)in_vec;
    vl = __riscv_vsetvl_e32m8(size2);
    vfloat32m8_t vMax = __riscv_vle32_v_f32m8(in_vec2, vl);
    in_vec2 += vl;
    size2 -= vl;
    while(size2 > 0)
    {
        vl =__riscv_vsetvl_e32m8(size2);
        vfloat32m8_t vTmp = __riscv_vle32_v_f32m8(in_vec2, vl);
        vMax = __riscv_vfmax(vMax, vTmp, vl);
        in_vec2 += vl;
        size2 -= vl;
    }
    vfloat32m1_t vMax_e0;       //the element at v[0]
    vMax_e0 = __riscv_vfmv_v_f_f32m1(__FLT16_MIN__, size);
    vMax_e0 = __riscv_vfredmax_tu(vMax_e0, vMax, vMax_e0, size);
    max = __riscv_vfmv_f(vMax_e0);

    //calculate the exp and sum
    vfloat32m4_t vSum = __riscv_vfmv_v_f_f32m4(0.f, size);
    vfloat32m1_t vOut_e0 = __riscv_vfmv_v_f_f32m1(0.f, size);       //the element at v[0]
    out_vec2 = out_vec;
    size2 = size;
    while(size2 > 0)
    {
        vfloat32m4_t vIn_f32;
        vfloat32m4_t vA, vB, vC, vD, vX2, vX4, vPoly_f32;
        vint32m4_t vPoly_i32;

        vl = __riscv_vsetvl_e32m4(size2);
        vIn_f32 = __riscv_vle32_v_f32m4(in_vec, vl);
        vIn_f32 = __riscv_vfsub(vIn_f32, max, vl);
        vIn_f32 = __riscv_vfmax(vIn_f32, exp_min, vl);
        vIn_f32 = __riscv_vfmin(vIn_f32, exp_max, vl);

        //--- exp_f32 begin ---
        // Perform range reduction [-log(2),log(2)]
        vfloat32m4_t vm = __riscv_vfmul(vIn_f32, inv_ln2, vl);          //x * inv_ln2;
        vint32m4_t vm_int = __riscv_vfcvt_rtz_x(vm, vl);                //m (integer type)
        vm = __riscv_vfcvt_f(vm_int, vl);                               //m (float type)
        vm = __riscv_vfnmsub_tu(vm, ln2, vIn_f32, vl);                  //val

        //--- taylor_poly_f32 begin ---
        vA = __riscv_vfmv_v_f_f32m4(exp_coe0, vl);                      //A = exp_coe0
        vA = __riscv_vfmacc_tu(vA, exp_coe4, vm, vl);                   //A = exp_coe0 + x * exp_coe4
        vB = __riscv_vfmv_v_f_f32m4(exp_coe2, vl);                      //B = exp_coe2
        vB = __riscv_vfmacc_tu(vB, exp_coe6, vm, vl);                   //B = exp_coe2 + x * exp_coe6
        vC = __riscv_vfmv_v_f_f32m4(exp_coe1, vl);                      //C = exp_coe1
        vC = __riscv_vfmacc_tu(vC, exp_coe5, vm, vl);                   //C = exp_coe1 + x * exp_coe5
        vD = __riscv_vfmv_v_f_f32m4(exp_coe3, vl);                      //D = exp_coe3
        vD = __riscv_vfmacc_tu(vD, exp_coe7, vm, vl);                   //D = exp_coe3 + x * exp_coe7
        vX2 = __riscv_vfmul(vm, vm, vl);                                //x2
        vm_int = __riscv_vsll(vm_int, 23, vl);                          //m2
        vX4 = __riscv_vfmul(vX2, vX2, vl);                              //x4
        vA = __riscv_vfmacc_tu(vA, vB, vX2, vl);                        //A + B * x2
        vC = __riscv_vfmacc_tu(vC, vD, vX2, vl);                        //C + D * x2
        vA = __riscv_vfmacc_tu(vA, vC, vX4, vl);                        //(A + B * x2) + (C + D * x2) * x4
        //--- taylor_poly_f32 end ---

        // Reconstruct
        vPoly_i32 = __riscv_vreinterpret_v_f32m4_i32m4(vA);
        vPoly_i32 = __riscv_vsadd(vPoly_i32, vm_int, vl);
        vPoly_f32 = __riscv_vreinterpret_v_i32m4_f32m4(vPoly_i32);
        //--- exp_f32 end ---

        __riscv_vse32(out_vec2, vPoly_f32, vl);
        vSum = __riscv_vfadd_vv_f32m4(vSum, vPoly_f32, vl);             //accumulate sum_f32
        in_vec += vl;
        out_vec2 += vl;
        size2 -= vl;
    }
    vOut_e0 = __riscv_vfredusum_tu(vOut_e0, vSum, vOut_e0, size);
    #ifdef ENA_FAST_ALGO
        vl = __riscv_vsetvl_e32m1(1);
        vOut_e0 = __riscv_vfrec7(vOut_e0, vl);
    #endif
    sum = __riscv_vfmv_f(vOut_e0);

    //divide the output by sum
    vl = __riscv_vsetvlmax_e32m8();
    ele_per_loop = vl << 1;
    size2 = size;
    while (size2 >= ele_per_loop)
    {
        vfloat32m8_t vOut1, vOut2;
        vOut1 = __riscv_vle32_v_f32m8(out_vec, vl);
        float32_t* out_vec2 = (float32_t*)out_vec + vl;
        vOut2 = __riscv_vle32_v_f32m8(out_vec2, vl);

#ifdef ENA_FAST_ALGO
        vOut1 = __riscv_vfmul(vOut1, sum, vl);
        vOut2 = __riscv_vfmul(vOut2, sum, vl);
        __riscv_vse32(out_vec, vOut1, vl);
        __riscv_vse32(out_vec2, vOut2, vl);
        out_vec += ele_per_loop;
#else
        vOut1 = __riscv_vfdiv(vOut1, sum, vl);
        vOut2 = __riscv_vfdiv(vOut2, sum, vl);
        __riscv_vse32(out_vec, vOut1, vl);
        __riscv_vse32(out_vec2, vOut2, vl);
        out_vec += ele_per_loop;
#endif
        size2 -= ele_per_loop;
    }

    while(size2 > 0)
    {
        vfloat32m8_t vOut;
        vl = __riscv_vsetvl_e32m8(size2);
        vOut = __riscv_vle32_v_f32m8(out_vec, vl);
#ifdef ENA_FAST_ALGO
        vOut = __riscv_vfmul(vOut, sum, vl);
#else
        vOut = __riscv_vfdiv(vOut, sum, vl);
#endif
        __riscv_vse32(out_vec, vOut, vl);
        out_vec += vl;
        size2 -= vl;
    }
#else
    //find the maximun
    in_vec2 = (float32_t *)in_vec;
    NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
    NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec2);
    in_vec2 += vl;
    size2 -= vl;
    while(size2 > 0)
    {
        NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VLE32_V(NDS_VEC_V8, in_vec2);
        in_vec2 += vl;
        size2 -= vl;
        NDS_VEC_VFMAX_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);
    }
    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note teh avl here
    NDS_VEC_VFREDMAX_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V0);
    NDS_VEC_VFMV_F_S(max, NDS_VEC_V0);

    //calculate the exp and sum
    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
    NDS_VEC_VAND_VI(NDS_VEC_V28, NDS_VEC_V28, 0);   //init sum
    in_vec2 = (float32_t *)in_vec;
    out_vec2 = out_vec;
    size2 = size;
    while(size2 > 0)
    {
        NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VLE32_V(NDS_VEC_V12, in_vec2);
        NDS_VEC_VFSUB_VF(NDS_VEC_V12, NDS_VEC_V12, max);
        size2 -= vl;

        //--- exp_f32 begin ---
        NDS_VEC_VFMAX_VF(NDS_VEC_V12, NDS_VEC_V12, exp_min);
        NDS_VEC_VFMIN_VF(NDS_VEC_V12, NDS_VEC_V12, exp_max);
        // Perform range reduction [-log(2),log(2)]
        NDS_VEC_VFMUL_VF(NDS_VEC_V0, NDS_VEC_V12, inv_ln2);         //x * inv_ln2;
        NDS_VEC_VFCVT_RTZ_X_F_V(NDS_VEC_V0, NDS_VEC_V0);            //m (integer type)
        NDS_VEC_VFCVT_F_X_V(NDS_VEC_V4, NDS_VEC_V0);                //m (float type)
        NDS_VEC_VFNMSUB_VF(NDS_VEC_V4, ln2, NDS_VEC_V12);           //val

        //--- taylor_poly_f32 begin ---
        NDS_VEC_VFMV_V_F(NDS_VEC_V8, exp_coe0);                     //A = exp_coe0
        NDS_VEC_VFMACC_VF(NDS_VEC_V8, exp_coe4, NDS_VEC_V4);        //A = exp_coe0 + x * exp_coe4
        NDS_VEC_VFMV_V_F(NDS_VEC_V12, exp_coe2);                    //B = exp_coe2
        NDS_VEC_VFMACC_VF(NDS_VEC_V12, exp_coe6, NDS_VEC_V4);       //B = exp_coe2 + x * exp_coe6
        NDS_VEC_VFMV_V_F(NDS_VEC_V16, exp_coe1);                    //C = exp_coe1
        NDS_VEC_VFMACC_VF(NDS_VEC_V16, exp_coe5, NDS_VEC_V4);       //C = exp_coe1 + x * exp_coe5
        NDS_VEC_VFMV_V_F(NDS_VEC_V20, exp_coe3);                    //D = exp_coe3
        NDS_VEC_VFMACC_VF(NDS_VEC_V20, exp_coe7, NDS_VEC_V4);       //D = exp_coe3 + x * exp_coe7
        NDS_VEC_VFMUL_VV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V4);       //x2
        NDS_VEC_VSLL_VX(NDS_VEC_V24, NDS_VEC_V0, 23);               //m2
        NDS_VEC_VFMACC_VV(NDS_VEC_V8, NDS_VEC_V12, NDS_VEC_V4);     //A + B * x2
        NDS_VEC_VFMACC_VV(NDS_VEC_V16, NDS_VEC_V20, NDS_VEC_V4);    //C + D * x2
        NDS_VEC_VFMUL_VV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V4);       //x4
        NDS_VEC_VFMACC_VV(NDS_VEC_V8, NDS_VEC_V16, NDS_VEC_V4);     //(A + B * x2) + (C + D * x2) * x4
        //--- taylor_poly_f32 end ---

        NDS_VEC_VSADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V24);
        //--- exp_f32 end ---

        NDS_VEC_VFADD_VV(NDS_VEC_V28, NDS_VEC_V28, NDS_VEC_V8);     //accumulate sum_f32
        NDS_VEC_VSE32_V(NDS_VEC_V8, out_vec2);
        in_vec2 += vl;
        out_vec2 += vl;
    }
    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VAND_VI(NDS_VEC_V20, NDS_VEC_V20, 0);   //for redsum
    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
    NDS_VEC_VFREDSUM_VS(NDS_VEC_V20, NDS_VEC_V28, NDS_VEC_V20);
#ifdef ENA_FAST_ALGO
    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VFRECE7_V(NDS_VEC_V20, NDS_VEC_V20);
#endif
    NDS_VEC_VFMV_F_S(sum, NDS_VEC_V20);

    //divide the output by sum
    NDS_VEC_VSETVLI(ele_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
    ele_per_loop <<= 1;
    size2 = size;
    NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
    while (size2 >= ele_per_loop)
    {
        float32_t* out_vec2 = (float32_t*)out_vec + vl;
        NDS_VEC_VLE32_V(NDS_VEC_V0, out_vec);
        NDS_VEC_VLE32_V(NDS_VEC_V8, out_vec2);
#ifdef ENA_FAST_ALGO
        NDS_VEC_VFMUL_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
        NDS_VEC_VFMUL_VF(NDS_VEC_V8, NDS_VEC_V8, sum);
#else
        NDS_VEC_VFDIV_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
        NDS_VEC_VFDIV_VF(NDS_VEC_V8, NDS_VEC_V8, sum);
#endif
        NDS_VEC_VSE32_V(NDS_VEC_V0, out_vec);
        out_vec += ele_per_loop;
        NDS_VEC_VSE32_V(NDS_VEC_V8, out_vec2);
        size2 -= ele_per_loop;
    }
    while(size2 > 0)
    {
        NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VLE32_V(NDS_VEC_V0, out_vec);
#ifdef ENA_FAST_ALGO
        NDS_VEC_VFMUL_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
#else
        NDS_VEC_VFDIV_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
#endif
        NDS_VEC_VSE32_V(NDS_VEC_V0, out_vec);
        out_vec += vl;
        size2 -= vl;
    }
#endif
#else
    float32_t sum = 0;
    long i;

    float32_t max = in_vec[0];
    for(i = 1; i < size; i++)
    {
        max = (in_vec[i] > max)? in_vec[i] : max;
    }

    for(i = 0; i < size; i++)
    {
        out_vec[i] = exp_f32(in_vec[i] - max);
        sum += out_vec[i];
    }

    for(i = 0; i < size; i++)
    {
        out_vec[i] = out_vec[i] / sum;
    }
#endif
#endif  //ENA_EMPTY_FUN

    return 0;
}

