 20→/** @file*/
 21→
 22→#include "internal_nn_math.h"
 23→
 24→//// Basic Operation Functions
 25→
 26→int32_t riscv_nn_ew_mul_s8_asym(const int8_t * in_vec1,
 27→                                const int8_t * in_vec2,
 28→                                const int32_t in_offset1,
 29→                                const int32_t in_offset2,
 30→                                int8_t * out_vec,
 31→                                const int32_t out_offset,
 32→                                const int32_t out_scale,
 33→                                const int32_t out_shift,
 34→                                const int32_t act_min,
 35→                                const int32_t act_max,
 36→                                const uint32_t size)
 37→{
 38→#ifdef ENA_EMPTY_FUN
 39→    //empty body
 40→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
 41→    const long total_out_shift = 31 - out_shift - 1;
 42→    long avl = size;
 43→    long vl;
 44→
 45→    while(avl > 0)
 46→    {
 47→        vl = __riscv_vsetvl_e8m1(avl);
 48→        vint8m1_t vA1_i8 = __riscv_vle8_v_i8m1(in_vec1, vl);
 49→        vint8m1_t vB1_i8 = __riscv_vle8_v_i8m1(in_vec2, vl);
 50→        vl = __riscv_vsetvl_e32m4(avl);
 51→        vint32m4_t vInput1_i32 = __riscv_vsext_vf4(vA1_i8, vl);
 52→        vint32m4_t vInput2_i32 = __riscv_vsext_vf4(vB1_i8, vl);
 53→        vint32m4_t vInput1_sum = __riscv_vadd(vInput1_i32, in_offset1, vl);
 54→        vint32m4_t vInput2_sum = __riscv_vadd(vInput2_i32, in_offset2, vl);
 55→        vint32m4_t vProduct_i32 = __riscv_vmul(vInput1_sum, vInput2_sum, vl);
 56→
 57→        vint64m8_t vProduct_i64 = __riscv_vwmul(vProduct_i32, out_scale, vl);
 58→        vint32m4_t vProduct_nsra_i32 = __riscv_vnsra(vProduct_i64, total_out_shift, vl);
 59→        vint32m4_t vProduct_ssra_i32 = __riscv_vssra(vProduct_nsra_i32, 1, __RISCV_VXRM_RNU, vl);
 60→
 61→        vint32m4_t vSum = __riscv_vadd(vProduct_ssra_i32, out_offset, vl);
 62→        vSum = __riscv_vmax(vSum, act_min, vl);
 63→        vSum = __riscv_vmin(vSum, act_max, vl);
 64→
 65→        vl = __riscv_vsetvl_e16m2(vl);
 66→        vint16m2_t vSum_nsra_i16 = __riscv_vnsra(vSum, 0, vl);
 67→        vl = __riscv_vsetvl_e8m1(vl);
 68→        vint8m1_t vSum_nsra_i8 = __riscv_vnsra(vSum_nsra_i16, 0, vl);
 69→        __riscv_vse8(out_vec, vSum_nsra_i8, vl);
 70→        in_vec1 += vl;
 71→        in_vec2 += vl;
 72→        out_vec += vl;
 73→        avl -= vl;
 74→    }
 75→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ELEN64)
 76→    uint32_t loop = size;
 77→    const long total_out_shift = 31 - out_shift - 1;
 78→    long vl;
 79→
 80→    while(loop > 0)
 81→    {
 82→        NDS_VEC_VSETVLI(vl, loop, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
 83→        NDS_VEC_VLE8_V(NDS_VEC_V8, in_vec1);
 84→        NDS_VEC_VLE8_V(NDS_VEC_V12, in_vec2);
 85→        NDS_VEC_VSEXT_VF4(NDS_VEC_V0, NDS_VEC_V8);
 86→        NDS_VEC_VSEXT_VF4(NDS_VEC_V4, NDS_VEC_V12);
 87→        NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset1);
 88→        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, in_offset2);
 89→        NDS_VEC_VMUL_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V4);
 90→
 91→        NDS_VEC_VWMUL_VX(NDS_VEC_V8, NDS_VEC_V0, out_scale);
 92→        NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, total_out_shift);
 93→        NDS_VEC_VSSRA_VI(NDS_VEC_V0, NDS_VEC_V8, 1);
 94→
 95→        NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, out_offset);
 96→        NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, act_min);
 97→        NDS_VEC_VMIN_VX(NDS_VEC_V0, NDS_VEC_V0, act_max);
 98→
 99→        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
100→        NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
101→        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
102→        NDS_VEC_VNSRA_WI(NDS_VEC_V16, NDS_VEC_V0, 0);
103→        NDS_VEC_VSE8_V(NDS_VEC_V16, out_vec);
104→        in_vec1 += vl;
105→        in_vec2 += vl;
106→        out_vec += vl;
107→        loop -= vl;
108→    }
109→#elif defined(ENA_DSP_ISA_64)
110→    uint32_t loop;
111→    int32_t in1, in2, out;
112→
113→    if (out_shift >= 0)
114→    {
115→        long_t in1_31, in1_20, in2_31, in2_20;
116→        long_t offset1_dual, offset2_dual;
117→        long_t mul;
118→
119→        offset1_dual = NDS_DSP_PKBB16(in_offset1, in_offset1);
120→        offset2_dual = NDS_DSP_PKBB16(in_offset2, in_offset2);
121→
122→        loop = size >> 2;
123→        while (loop > 0)
124→        {
125→            long_t in1_s8x4 = *__SIMD32(in_vec1)++;
126→            long_t in2_s8x4 = *__SIMD32(in_vec2)++;
