/** @file*/

#include "internal_nn_math.h"

//// Basic Operation Functions

int32_t riscv_nn_ew_mul_s8_asym(const int8_t * in_vec1,
                                const int8_t * in_vec2,
                                const int32_t in_offset1,
                                const int32_t in_offset2,
                                int8_t * out_vec,
                                const int32_t out_offset,
                                const int32_t out_scale,
                                const int32_t out_shift,
                                const int32_t act_min,
                                const int32_t act_max,
                                const uint32_t size)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
    const long total_out_shift = 31 - out_shift - 1;
    long avl = size;
    long vl;

    while(avl > 0)
    {
        vl = __riscv_vsetvl_e8m1(avl);
        vint8m1_t vA1_i8 = __riscv_vle8_v_i8m1(in_vec1, vl);
        vint8m1_t vB1_i8 = __riscv_vle8_v_i8m1(in_vec2, vl);
        vl = __riscv_vsetvl_e32m4(avl);
        vint32m4_t vInput1_i32 = __riscv_vsext_vf4(vA1_i8, vl);
        vint32m4_t vInput2_i32 = __riscv_vsext_vf4(vB1_i8, vl);
        vint32m4_t vInput1_sum = __riscv_vadd(vInput1_i32, in_offset1, vl);
        vint32m4_t vInput2_sum = __riscv_vadd(vInput2_i32, in_offset2, vl);
        vint32m4_t vProduct_i32 = __riscv_vmul(vInput1_sum, vInput2_sum, vl);

        vint64m8_t vProduct_i64 = __riscv_vwmul(vProduct_i32, out_scale, vl);
        vint32m4_t vProduct_nsra_i32 = __riscv_vnsra(vProduct_i64, total_out_shift, vl);
        vint32m4_t vProduct_ssra_i32 = __riscv_vssra(vProduct_nsra_i32, 1, __RISCV_VXRM_RNU, vl);

        vint32m4_t vSum = __riscv_vadd(vProduct_ssra_i32, out_offset, vl);
        vSum = __riscv_vmax(vSum, act_min, vl);
        vSum = __riscv_vmin(vSum, act_max, vl);

        vl = __riscv_vsetvl_e16m2(vl);
        vint16m2_t vSum_nsra_i16 = __riscv_vnsra(vSum, 0, vl);
        vl = __riscv_vsetvl_e8m1(vl);
        vint8m1_t vSum_nsra_i8 = __riscv_vnsra(vSum_nsra_i16, 0, vl);
        __riscv_vse8(out_vec, vSum_nsra_i8, vl);
        in_vec1 += vl;
        in_vec2 += vl;
        out_vec += vl;
        avl -= vl;
    }
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ELEN64)
    uint32_t loop = size;
    const long total_out_shift = 31 - out_shift - 1;
    long vl;

    while(loop > 0)
    {
        NDS_VEC_VSETVLI(vl, loop, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VLE8_V(NDS_VEC_V8, in_vec1);
        NDS_VEC_VLE8_V(NDS_VEC_V12, in_vec2);
        NDS_VEC_VSEXT_VF4(NDS_VEC_V0, NDS_VEC_V8);
        NDS_VEC_VSEXT_VF4(NDS_VEC_V4, NDS_VEC_V12);
        NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset1);
        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, in_offset2);
        NDS_VEC_VMUL_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V4);

        NDS_VEC_VWMUL_VX(NDS_VEC_V8, NDS_VEC_V0, out_scale);
        NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, total_out_shift);
        NDS_VEC_VSSRA_VI(NDS_VEC_V0, NDS_VEC_V8, 1);

        NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, out_offset);
        NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, act_min);
        NDS_VEC_VMIN_VX(NDS_VEC_V0, NDS_VEC_V0, act_max);

        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNSRA_WI(NDS_VEC_V16, NDS_VEC_V0, 0);
        NDS_VEC_VSE8_V(NDS_VEC_V16, out_vec);
        in_vec1 += vl;
        in_vec2 += vl;
        out_vec += vl;
        loop -= vl;
    }
#elif defined(ENA_DSP_ISA_64)
    uint32_t loop;
    int32_t in1, in2, out;

    if (out_shift >= 0)
    {
        long_t in1_31, in1_20, in2_31, in2_20;
        long_t offset1_dual, offset2_dual;
        long_t mul;

        offset1_dual = NDS_DSP_PKBB16(in_offset1, in_offset1);
        offset2_dual = NDS_DSP_PKBB16(in_offset2, in_offset2);

        loop = size >> 2;
        while (loop > 0)
        {
            long_t in1_s8x4 = *__SIMD32(in_vec1)++;
            long_t in2_s8x4 = *__SIMD32(in_vec2)++;
            in1_31 = NDS_DSP_SUNPKD831(in1_s8x4);
            in1_20 = NDS_DSP_SUNPKD820(in1_s8x4);
            in2_31 = NDS_DSP_SUNPKD831(in2_s8x4);
            in2_20 = NDS_DSP_SUNPKD820(in2_s8x4);

            in1_31 = NDS_DSP_ADD16(in1_31, offset1_dual);
            in1_20 = NDS_DSP_ADD16(in1_20, offset1_dual);

            in2_31 = NDS_DSP_ADD16(in2_31, offset2_dual);
            in2_20 = NDS_DSP_ADD16(in2_20, offset2_dual);

            // unroll-1
            mul = NDS_DSP_SMUL16(in1_20, in2_20);
            out = nn_requantize(mul, out_scale, out_shift) + out_offset;
            out = nn_clip_any(out, act_min, act_max);
            *out_vec = out;

            // unroll-3
            out = nn_requantize((mul>>32), out_scale, out_shift) + out_offset;
            out = nn_clip_any(out, act_min, act_max);
            *(out_vec+2) = out;

            // unroll-2
            mul = NDS_DSP_SMUL16(in1_31, in2_31);
            out = nn_requantize(mul, out_scale, out_shift) + out_offset;
            out = nn_clip_any(out, act_min, act_max);
            *(out_vec+1) = out;

            // unroll-4
            out = nn_requantize((mul>>32), out_scale, out_shift) + out_offset;
            out = nn_clip_any(out, act_min, act_max);
            *(out_vec+3) = out;

            out_vec += 4;
            loop--;
        }
    }
    else
    {
        long_t in1_31 = 0, in1_20 = 0, in2_31 = 0, in2_20 = 0;
        long_t offset1_dual = NDS_DSP_PKBB16(in_offset1, in_offset1);
        long_t offset2_dual = NDS_DSP_PKBB16(in_offset2, in_offset2);
        uint32_t out_rshift = -out_shift;
        long_t out1_s32x2 = 0, out2_s32x2 = 0;
        long_t out_offset_s32x2 = NDS_DSP_PKBB32(out_offset, out_offset);
        long_t max_s32x2 = NDS_DSP_PKBB32(act_max, act_max);
        long_t min_s32x2 = NDS_DSP_PKBB32(act_min, act_min);
        long_t out_scale_s32x2  = NDS_DSP_PKBB32(out_scale, out_scale);
        loop = size >> 2;
        while (loop)
        {
            long_t in1_s8x4 = *__SIMD32(in_vec1)++;
            long_t in2_s8x4 = *__SIMD32(in_vec2)++;
            in1_31 = NDS_DSP_SUNPKD831(in1_s8x4);
            in1_20 = NDS_DSP_SUNPKD820(in1_s8x4);
            in2_31 = NDS_DSP_SUNPKD831(in2_s8x4);
            in2_20 = NDS_DSP_SUNPKD820(in2_s8x4);
            in1_31 = NDS_DSP_ADD16(in1_31, offset1_dual);
            in1_20 = NDS_DSP_ADD16(in1_20, offset1_dual);
            in2_31 = NDS_DSP_ADD16(in2_31, offset2_dual);
            in2_20 = NDS_DSP_ADD16(in2_20, offset2_dual);
            out1_s32x2 = NDS_DSP_SMUL16(in1_20, in2_20);
            out2_s32x2 = NDS_DSP_SMUL16(in1_31, in2_31);
            out1_s32x2 = NDS_DSP_KWMMUL(out1_s32x2, out_scale_s32x2);
            out2_s32x2 = NDS_DSP_KWMMUL(out2_s32x2, out_scale_s32x2);
            out1_s32x2 = NDS_DSP_SRA32_U(out1_s32x2, out_rshift);
            out2_s32x2 = NDS_DSP_SRA32_U(out2_s32x2, out_rshift);
            out1_s32x2 = NDS_DSP_ADD32(out1_s32x2, out_offset_s32x2);
            out2_s32x2 = NDS_DSP_ADD32(out2_s32x2, out_offset_s32x2);
            out1_s32x2 = NDS_DSP_SMAX32(out1_s32x2, min_s32x2);
            out2_s32x2 = NDS_DSP_SMAX32(out2_s32x2, min_s32x2);
            out1_s32x2 = NDS_DSP_SMIN32(out1_s32x2, max_s32x2);
            out2_s32x2 = NDS_DSP_SMIN32(out2_s32x2, max_s32x2);
            *out_vec++ = (int8_t)((out1_s32x2));
            *out_vec++ = (int8_t)((out2_s32x2));
            *out_vec++ = (int8_t)((out1_s32x2>>32));
            *out_vec++ = (int8_t)((out2_s32x2>>32));
            loop--;
        }
    }

    loop = size & 0x3;
    while (loop > 0)
    {
        in1 = *in_vec1++ + in_offset1;
        in2 = *in_vec2++ + in_offset2;

        out = in1 * in2;
        out = nn_requantize(out, out_scale, out_shift) + out_offset;
        out = nn_clip_any(out, act_min, act_max);

        *out_vec++ = out;
        loop--;
    }
#elif defined(ENA_DSP_ISA)
    int32_t in1_31, in1_20, in2_31, in2_20;
    int32_t offset1_dual, offset2_dual;
    uint64_t mul;
    int32_t in1, in2, out;

    offset1_dual = NDS_DSP_PKBB16(in_offset1, in_offset1);
    offset2_dual = NDS_DSP_PKBB16(in_offset2, in_offset2);

    long loop = size >> 2;
    while (loop > 0)
    {
        in_vec1 = read_and_pad_reordered((int8_t *)in_vec1, &in1_20, &in1_31);
        in_vec2 = read_and_pad_reordered((int8_t *)in_vec2, &in2_20, &in2_31);

        in1_31 = NDS_DSP_ADD16(in1_31, offset1_dual);
        in1_20 = NDS_DSP_ADD16(in1_20, offset1_dual);

        in2_31 = NDS_DSP_ADD16(in2_31, offset2_dual);
        in2_20 = NDS_DSP_ADD16(in2_20, offset2_dual);

        // unroll-1
        mul = NDS_DSP_SMUL16(in1_20, in2_20);
        out = nn_requantize(mul, out_scale, out_shift) + out_offset;
        out = nn_clip_any(out, act_min, act_max);
        *out_vec = out;

        // unroll-3
        out = nn_requantize((mul>>32), out_scale, out_shift) + out_offset;
        out = nn_clip_any(out, act_min, act_max);
        *(out_vec+2) = out;

        // unroll-2
        mul = NDS_DSP_SMUL16(in1_31, in2_31);
        out = nn_requantize(mul, out_scale, out_shift) + out_offset;
        out = nn_clip_any(out, act_min, act_max);
        *(out_vec+1) = out;

        // unroll-4
        out = nn_requantize((mul>>32), out_scale, out_shift) + out_offset;
        out = nn_clip_any(out, act_min, act_max);
        *(out_vec+3) = out;

        out_vec += 4;
        loop--;
    }

    loop = size & 0x3;
    while (loop > 0)
    {
        in1 = *in_vec1++ + in_offset1;
        in2 = *in_vec2++ + in_offset2;

        out = in1 * in2;
        out = nn_requantize(out, out_scale, out_shift) + out_offset;
        out = nn_clip_any(out, act_min, act_max);

        *out_vec++ = out;
        loop--;
    }
#else
    long loop = size;
    int32_t in1, in2, out;
    while (loop > 0)
    {
        in1 = *in_vec1++ + in_offset1;
        in2 = *in_vec2++ + in_offset2;

        out = in1 * in2;
        out = nn_requantize(out, out_scale, out_shift) + out_offset;
        out = nn_clip_any(out, act_min, act_max);

        *out_vec++ = out;
        loop--;
    }
#endif

  return 0;
}

