  60→    NDS_VEC_VAND_VX(NDS_VEC_V10, NDS_VEC_V1, 0x0000FFFF);   //8n   8n+2 index mask (for acc1)
  61→    NDS_VEC_VAND_VX(NDS_VEC_V11, NDS_VEC_V1, 0xFFFF0000);   //8n+1 8n+3 index mask (for acc2)
  62→    NDS_VEC_VAND_VX(NDS_VEC_V12, NDS_VEC_V2, 0x0000FFFF);   //8n+4 8n+6 index mask (for acc3)
  63→    NDS_VEC_VAND_VX(NDS_VEC_V13, NDS_VEC_V2, 0xFFFF0000);   //8n+5 8n+7 index mask (for acc4)
  64→
  65→    while (rowCnt)
  66→    {
  67→        //set SEW for 1st time VMV_S_X
  68→        //LMUL=2 is just for clear v4~v5 (vmv ignores LMUL)
  69→        NDS_VEC_VSETVLI_E32_M2(vl, colCnt);
  70→
  71→        uint32_t colCnt2 = colCnt;
  72→        pA = (q7_t*)in_tmp_buf;
  73→        /* init sum with bias */
  74→        int32_t sum = *pBias++;
  75→        int32_t sum2 = *pBias++;
  76→        int32_t sum3 = *pBias++;
  77→        int32_t sum4 = *pBias++;
  78→
  79→        //init
  80→        NDS_VEC_VMV_S_X(NDS_VEC_V6, sum);
  81→        NDS_VEC_VMV_S_X(NDS_VEC_V7, sum2);
  82→        NDS_VEC_VMV_S_X(NDS_VEC_V8, sum3);
  83→        NDS_VEC_VMV_S_X(NDS_VEC_V9, sum4);
  84→        //clear v4~v5 (tmp acc)
  85→        NDS_VEC_VAND_VX(NDS_VEC_V4, NDS_VEC_V4, 0);
  86→
  87→        while (colCnt2)
  88→        {
  89→            NDS_VEC_VSETVLI_E16(vl, colCnt2);
  90→            NDS_VEC_VLB_V(NDS_VEC_V1, pA);
  91→            NDS_VEC_VLB_V(NDS_VEC_V2, pB);
  92→            NDS_VEC_VWMACC_VV(NDS_VEC_V4, NDS_VEC_V1, NDS_VEC_V2);
  93→            colCnt2 -= vl;
  94→            pA += vl;
  95→            pB += vl;
  96→        }
  97→
  98→        NDS_VEC_VSETVLI_E32_M2(vl, colCnt);   //note the avl here
  99→        NDS_VEC_VMCPY_M(NDS_VEC_V0, NDS_VEC_V10);
 100→        NDS_VEC_MSK_VREDSUM_VS(NDS_VEC_V6, NDS_VEC_V4, NDS_VEC_V6);
 101→        NDS_VEC_VMCPY_M(NDS_VEC_V0, NDS_VEC_V11);
 102→        NDS_VEC_MSK_VREDSUM_VS(NDS_VEC_V7, NDS_VEC_V4, NDS_VEC_V7);
 103→        NDS_VEC_VMCPY_M(NDS_VEC_V0, NDS_VEC_V12);
 104→        NDS_VEC_MSK_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V4, NDS_VEC_V8);
 105→        NDS_VEC_VMCPY_M(NDS_VEC_V0, NDS_VEC_V13);
 106→        NDS_VEC_MSK_VREDSUM_VS(NDS_VEC_V9, NDS_VEC_V4, NDS_VEC_V9);
 107→
 108→        //rest part
 109→        NDS_VEC_VSETVLI_E32(vl, 4);     //4: 4 acc
 110→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V7, 1);
 111→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V8, 2);
 112→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V9, 3);
 113→
 114→        colCnt2 = size & 0x3;
 115→        while(colCnt2)
 116→        {
 117→            q7_t inV = *pA++;
 118→            NDS_VEC_VLB_V(NDS_VEC_V3, pB);
 119→            NDS_VEC_VMACC_VX(NDS_VEC_V6, inV, NDS_VEC_V3);
 120→            pB += 4;
 121→            colCnt2--;
 122→        }
 123→
 124→        NDS_VEC_VSRA_VX(NDS_VEC_V6, NDS_VEC_V6, pre_rshift);
 125→        NDS_VEC_VMUL_VX(NDS_VEC_V6, NDS_VEC_V6, out_scale);
 126→        NDS_VEC_VADD_VX(NDS_VEC_V6, NDS_VEC_V6, NN_ROUND(post_rshift));
 127→        NDS_VEC_VSRA_VX(NDS_VEC_V6, NDS_VEC_V6, post_rshift);
 128→        NDS_VEC_VMAX_VX(NDS_VEC_V6, NDS_VEC_V6, Q15_MIN);
 129→        NDS_VEC_VMIN_VX(NDS_VEC_V6, NDS_VEC_V6, Q15_MAX);
