 133→    }
 134→
 135→    NDS_VEC_VSETVLI_E32_M2(vl, size);
 136→    rowCnt = wt_row_num & 0x3;
 137→    while (rowCnt)
 138→    {
 139→        int32_t sum = *pBias++;
 140→        pA = in_vec;
 141→        colCnt = size;
 142→
 143→        //init
 144→        NDS_VEC_VMV_S_X(NDS_VEC_V26, sum);
 145→        //clear v4~v5
 146→        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
 147→
 148→        while (colCnt != 0)
 149→        {
 150→            NDS_VEC_VSETVLI_E16(vl, colCnt);
 151→            NDS_VEC_VLB_V(NDS_VEC_V2, pA);
 152→            NDS_VEC_VLB_V(NDS_VEC_V3, pB);
 153→            NDS_VEC_VWMACC_VV(NDS_VEC_V4, NDS_VEC_V2, NDS_VEC_V3);
 154→            pB += vl;
 155→            pA += vl;
 156→            colCnt -= vl;
 157→        }
 158→
 159→        NDS_VEC_VSETVLI_E32_M2(vl, size);
 160→        NDS_VEC_VREDSUM_VS(NDS_VEC_V26, NDS_VEC_V4, NDS_VEC_V26);
 161→        NDS_VEC_VMV_X_S(sum, NDS_VEC_V26);
 162→        sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
 163→        *pO++ = NDS_ISA_SATS((sum >> post_rshift), 16);
 164→        rowCnt--;
 165→    }
 166→#else   //vqmacc
 167→#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
 168→    const q7_t *pB = wt_mat;
 169→    const q31_t *pBias = bias;
 170→    q15_t *pO = out_vec;
 171→    const q7_t *pA;
 172→    int32_t vl;
 173→    uint32_t rowCnt = wt_row_num >> 2;
 174→    uint32_t colCnt = (size >> 2) << 4;
 175→
 176→    nn_dup_s8_x4_reordered(in_vec, (q7_t*)in_tmp_buf, size);
 177→
 178→    //generate acc reduction mask
 179→    //Note. each element only occupy 1 bit
 180→    const uint64_t base_mask = 0x1111111111111111;
 181→    const uint64_t mask_1 = 0x1817161514111211;
 182→    const uint64_t mask_2 = 0x1817161511131112;
 183→    const uint64_t mask_3 = 0x1811161115141312;
 184→    const uint64_t mask_4 = 0x1118111615141312;
