 186→    vuint64m2_t vBase_mask_u64 = __riscv_vundefined_u64m2();
 187→    vuint64m2_t vA1 = __riscv_vundefined_u64m2();
 188→    vuint64m2_t vA2 = __riscv_vundefined_u64m2();
 189→    vuint64m2_t vA3 = __riscv_vundefined_u64m2();
 190→    vuint64m2_t vA4 = __riscv_vundefined_u64m2();
 191→    vBase_mask_u64 = __riscv_vmv_v_x_u64m2(base_mask, vl);
 192→    vA1 = __riscv_vmv_v_x_u64m2(mask_1, vl);
 193→    vA2 = __riscv_vmv_v_x_u64m2(mask_2, vl);
 194→    vA3 = __riscv_vmv_v_x_u64m2(mask_3, vl);
 195→    vA4 = __riscv_vmv_v_x_u64m2(mask_4, vl);
 196→    vuint8m2_t vBase_interpret = __riscv_vreinterpret_u8m2(vBase_mask_u64);
 197→    vuint8m2_t vInterpret_1 = __riscv_vreinterpret_u8m2(vA1);
 198→    vuint8m2_t vInterpret_2 = __riscv_vreinterpret_u8m2(vA2);
 199→    vuint8m2_t vInterpret_3 = __riscv_vreinterpret_u8m2(vA3);
 200→    vuint8m2_t vInterpret_4 = __riscv_vreinterpret_u8m2(vA4);
 201→    vl = __riscv_vsetvl_e8m2(colCnt);
 202→    vbool4_t vMask1_b4 = __riscv_vmseq(vBase_interpret, vInterpret_1, vl);   //8n   8n+2 index mask (for acc1)
 203→    vbool4_t vMask2_b4 = __riscv_vmseq(vBase_interpret, vInterpret_2, vl);   //8n+1 8n+3 index mask (for acc2)
 204→    vbool4_t vMask3_b4 = __riscv_vmseq(vBase_interpret, vInterpret_3, vl);   //8n+4 8n+6 index mask (for acc3)
 205→    vbool4_t vMask4_b4 = __riscv_vmseq(vBase_interpret, vInterpret_4, vl);   //8n+5 8n+7 index mask (for acc4)
 206→
 207→    while (rowCnt)
 208→    {
 209→        //set SEW for 1st time VMV_S_X
 210→        //LMUL=8 is just for clear acc
 211→        vl = __riscv_vsetvl_e32m8(colCnt);
 212→
 213→        uint32_t colCnt2 = colCnt;
 214→        pA = (q7_t*)in_tmp_buf;
 215→        /* init sum with bias */
