 223→        vint32m1_t vSum2_i32 = __riscv_vmv_s_x_i32m1(sum2, vl);
 224→        vint32m1_t vSum3_i32 = __riscv_vmv_s_x_i32m1(sum3, vl);
 225→        vint32m1_t vSum4_i32 = __riscv_vmv_s_x_i32m1(sum4, vl);
 226→        //clear acc
 227→        vint32m8_t vAcc_i32 = __riscv_vundefined_i32m8();
 228→        vAcc_i32 = __riscv_vand_tu(vAcc_i32, vAcc_i32, 0, vl);
 229→
 230→        while(colCnt2)
 231→        {
 232→            vl = __riscv_vsetvl_e8m2(colCnt2);
 233→            vint8m2_t vpA_i8 = __riscv_vundefined_i8m2();
 234→            vint8m2_t vpB_i8 = __riscv_vundefined_i8m2();
 235→            vpA_i8 = __riscv_vle8_tu(vpA_i8, pA, vl);
 236→            vpB_i8 = __riscv_vle8_tu(vpB_i8, pB, vl);
 237→            vAcc_i32 = __riscv_vqmacc_vv_i32m8_tu(vAcc_i32, vpA_i8, vpB_i8, vl);
 238→            colCnt2 -= vl;
 239→            pA += vl;
 240→            pB += vl;
 241→        }
 242→
 243→        vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
 244→        vint32m1_t vRedsum1_i32 = __riscv_vredsum(vMask1_b4, vAcc_i32, vSum1_i32, vl);
 245→        vint32m1_t vRedsum2_i32 = __riscv_vredsum(vMask2_b4, vAcc_i32, vSum2_i32, vl);
 246→        vint32m1_t vRedsum3_i32 = __riscv_vredsum(vMask3_b4, vAcc_i32, vSum3_i32, vl);
 247→        vint32m1_t vRedsum4_i32 = __riscv_vredsum(vMask4_b4, vAcc_i32, vSum4_i32, vl);
 248→
 249→        //rest part
 250→        vl = __riscv_vsetvl_e32m1(4);     //4: 4 acc
