 253→        vRedsum1_i32 = __riscv_vslideup(vRedsum1_i32, vRedsum4_i32, 3, vl);
 254→
 255→        vl = __riscv_vsetvl_e8mf4(4);   //4: 4 acc
 256→        colCnt2 = size & 0x3;
 257→        while(colCnt2)
 258→        {
 259→            q7_t inV = *pA++;
 260→            vint8mf4_t vpB_i8 = __riscv_vundefined_i8mf4();
