 272→        vRedsum1_i32 = __riscv_vmax(vRedsum1_i32, Q15_MIN, vl);
 273→        vRedsum1_i32 = __riscv_vmin(vRedsum1_i32, Q15_MAX, vl);
 274→
 275→        vl = __riscv_vsetvl_e16mf2(vl);
 276→        vint16mf2_t vResult_i16 = __riscv_vnsra(vRedsum1_i32, 0, vl);
 277→        __riscv_vse16(pO, vResult_i16, vl);
 278→        pO += 4;
 279→        rowCnt--;
 280→    }
 281→
 282→    vl = __riscv_vsetvl_e32m8(size);
 283→    rowCnt = wt_row_num & 0x3;
 284→    while (rowCnt)
 285→    {
 286→        int32_t sum = *pBias++;
 287→        pA = in_vec;
 288→        colCnt = size;
 289→
 290→        //init
 291→        vint32m1_t vSum1_i32 = __riscv_vmv_s_x_i32m1(sum, vl);
 292→        //clear acc
 293→        vint32m8_t vAcc_i32 = __riscv_vundefined_i32m8();
 294→        vAcc_i32 = __riscv_vand_tu(vAcc_i32, vAcc_i32, 0, vl);
 295→
 296→        while (colCnt != 0)
 297→        {
 298→            vl = __riscv_vsetvl_e8m2(colCnt);
 299→            vint8m2_t vpA_i8 = __riscv_vundefined_i8m2();
 300→            vint8m2_t vpB_i8 = __riscv_vundefined_i8m2();
 301→            vpA_i8 = __riscv_vle8_tu(vpA_i8, pA, vl);
 302→            vpB_i8 = __riscv_vle8_tu(vpB_i8, pB, vl);
 303→            vAcc_i32 = __riscv_vqmacc_vv_i32m8_tu(vAcc_i32, vpA_i8, vpB_i8, vl);
 304→            pB += vl;
 305→            pA += vl;
 306→            colCnt -= vl;
 307→        }
 308→
 309→        vl = __riscv_vsetvl_e32m8(size);
 310→        vint32m1_t vRedsum1_i32 = __riscv_vredsum(vAcc_i32, vSum1_i32, vl);
 311→        sum = __riscv_vmv_x(vRedsum1_i32);
 312→        sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
 313→        *pO++ = NDS_ISA_SATS((sum >> post_rshift), 16);
 314→        rowCnt--;
 315→    }
 316→#elif (NDS_VEC_RVV_VERSION >= 100)
 317→    const q7_t *pB = wt_mat;
 318→    const q31_t *pBias = bias;
 319→    q15_t *pO = out_vec;
 320→    const q7_t *pA;
 321→    int32_t vl;
 322→    uint32_t rowCnt = wt_row_num >> 2;
 323→    uint32_t colCnt = (size >> 2) << 4;
 324→
 325→    nn_dup_s8_x4_reordered(in_vec, (q7_t*)in_tmp_buf, size);
 326→
 327→    //generate acc reduction mask
 328→    //Note. each element only occupy 1 bit
 329→    NDS_VEC_VSETVLI_E8(vl, (colCnt+7)>>3);
 330→    NDS_VEC_VAND_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
 331→    NDS_VEC_VOR_VX(NDS_VEC_V20, NDS_VEC_V0, 0x05);   //8n   8n+2 index mask (for acc1)
 332→    NDS_VEC_VOR_VX(NDS_VEC_V21, NDS_VEC_V0, 0x0A);   //8n+1 8n+3 index mask (for acc2)
 333→    NDS_VEC_VOR_VX(NDS_VEC_V22, NDS_VEC_V0, 0x50);   //8n+4 8n+6 index mask (for acc3)
 334→    NDS_VEC_VOR_VX(NDS_VEC_V23, NDS_VEC_V0, 0xA0);   //8n+5 8n+7 index mask (for acc4)
 335→
 336→    while (rowCnt)
 337→    {
 338→        //set SEW for 1st time VMV_S_X
 339→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
 340→        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 341→
 342→        uint32_t colCnt2 = colCnt;
 343→        pA = (q7_t*)in_tmp_buf;
 344→        /* init sum with bias */
 345→        int32_t sum = *pBias++;
 346→        int32_t sum2 = *pBias++;
 347→        int32_t sum3 = *pBias++;
 348→        int32_t sum4 = *pBias++;
 349→
 350→        //init
 351→        NDS_VEC_VMV_S_X(NDS_VEC_V16, sum);
 352→        NDS_VEC_VMV_S_X(NDS_VEC_V17, sum2);
 353→        NDS_VEC_VMV_S_X(NDS_VEC_V18, sum3);
