/** @file*/

#include "internal_nn_math.h"
#include "riscv_nn_support.h"

//// FullyConnected Functions

int32_t riscv_nn_fc_s8_s16_s8_sym_bias_fast(const q7_t * in_vec,
                                        const q7_t * wt_mat,
                                        const uint16_t size,
                                        const uint16_t wt_row_num,
                                        const uint16_t pre_rshift,
                                        const uint16_t out_scale,
                                        const uint16_t post_rshift,
                                        const q31_t * bias,
                                        q15_t * out_vec,
                                        q15_t * in_tmp_buf)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#elif defined(ENA_VEC_ISA)
#if 0   //vwmacc
    const q7_t *pB = wt_mat;
    const q31_t *pBias = bias;
    q15_t *pO = out_vec;
    const q7_t *pA;
    int32_t vl;
    uint32_t rowCnt = wt_row_num >> 2;
    uint32_t colCnt = (size >> 2) << 4;

    nn_dup_s8_x4_reordered(in_vec, (q7_t*)in_tmp_buf, size);

    //generate acc reduction mask
    //(following generating mask codes could be optimized later if SEW>32 is supported)
    NDS_VEC_VSETVLI_E16(vl, colCnt);
    NDS_VEC_VID_V(NDS_VEC_V0);
    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x7);           //index mod 8
    NDS_VEC_VMSLE_VI(NDS_VEC_V1, NDS_VEC_V0, 0x3);          //8n ~ 8n+3
    NDS_VEC_VMSGT_VI(NDS_VEC_V2, NDS_VEC_V0, 0x3);          //8n+4 ~ 8n+7
    NDS_VEC_VSETVLI_E32(vl, colCnt >> 1);
    NDS_VEC_VAND_VX(NDS_VEC_V10, NDS_VEC_V1, 0x0000FFFF);   //8n   8n+2 index mask (for acc1)
    NDS_VEC_VAND_VX(NDS_VEC_V11, NDS_VEC_V1, 0xFFFF0000);   //8n+1 8n+3 index mask (for acc2)
    NDS_VEC_VAND_VX(NDS_VEC_V12, NDS_VEC_V2, 0x0000FFFF);   //8n+4 8n+6 index mask (for acc3)
    NDS_VEC_VAND_VX(NDS_VEC_V13, NDS_VEC_V2, 0xFFFF0000);   //8n+5 8n+7 index mask (for acc4)

    while (rowCnt)
    {
        //set SEW for 1st time VMV_S_X
        //LMUL=2 is just for clear v4~v5 (vmv ignores LMUL)
        NDS_VEC_VSETVLI_E32_M2(vl, colCnt);

        uint32_t colCnt2 = colCnt;
        pA = (q7_t*)in_tmp_buf;
        /* init sum with bias */
        int32_t sum = *pBias++;
        int32_t sum2 = *pBias++;
        int32_t sum3 = *pBias++;
        int32_t sum4 = *pBias++;

        //init
        NDS_VEC_VMV_S_X(NDS_VEC_V6, sum);
        NDS_VEC_VMV_S_X(NDS_VEC_V7, sum2);
        NDS_VEC_VMV_S_X(NDS_VEC_V8, sum3);
        NDS_VEC_VMV_S_X(NDS_VEC_V9, sum4);
        //clear v4~v5 (tmp acc)
        NDS_VEC_VAND_VX(NDS_VEC_V4, NDS_VEC_V4, 0);

        while (colCnt2)
        {
            NDS_VEC_VSETVLI_E16(vl, colCnt2);
            NDS_VEC_VLB_V(NDS_VEC_V1, pA);
            NDS_VEC_VLB_V(NDS_VEC_V2, pB);
            NDS_VEC_VWMACC_VV(NDS_VEC_V4, NDS_VEC_V1, NDS_VEC_V2);
            colCnt2 -= vl;
            pA += vl;
            pB += vl;
        }

        NDS_VEC_VSETVLI_E32_M2(vl, colCnt);   //note the avl here
        NDS_VEC_VMCPY_M(NDS_VEC_V0, NDS_VEC_V10);
        NDS_VEC_MSK_VREDSUM_VS(NDS_VEC_V6, NDS_VEC_V4, NDS_VEC_V6);
        NDS_VEC_VMCPY_M(NDS_VEC_V0, NDS_VEC_V11);
        NDS_VEC_MSK_VREDSUM_VS(NDS_VEC_V7, NDS_VEC_V4, NDS_VEC_V7);
        NDS_VEC_VMCPY_M(NDS_VEC_V0, NDS_VEC_V12);
        NDS_VEC_MSK_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V4, NDS_VEC_V8);
        NDS_VEC_VMCPY_M(NDS_VEC_V0, NDS_VEC_V13);
        NDS_VEC_MSK_VREDSUM_VS(NDS_VEC_V9, NDS_VEC_V4, NDS_VEC_V9);

        //rest part
        NDS_VEC_VSETVLI_E32(vl, 4);     //4: 4 acc
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V7, 1);
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V8, 2);
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V9, 3);

        colCnt2 = size & 0x3;
        while(colCnt2)
        {
            q7_t inV = *pA++;
            NDS_VEC_VLB_V(NDS_VEC_V3, pB);
            NDS_VEC_VMACC_VX(NDS_VEC_V6, inV, NDS_VEC_V3);
            pB += 4;
            colCnt2--;
        }

        NDS_VEC_VSRA_VX(NDS_VEC_V6, NDS_VEC_V6, pre_rshift);
        NDS_VEC_VMUL_VX(NDS_VEC_V6, NDS_VEC_V6, out_scale);
        NDS_VEC_VADD_VX(NDS_VEC_V6, NDS_VEC_V6, NN_ROUND(post_rshift));
        NDS_VEC_VSRA_VX(NDS_VEC_V6, NDS_VEC_V6, post_rshift);
        NDS_VEC_VMAX_VX(NDS_VEC_V6, NDS_VEC_V6, Q15_MIN);
        NDS_VEC_VMIN_VX(NDS_VEC_V6, NDS_VEC_V6, Q15_MAX);
        NDS_VEC_VSH_V(NDS_VEC_V6, pO);
        pO += 4;
        rowCnt--;
    }

    NDS_VEC_VSETVLI_E32_M2(vl, size);
    rowCnt = wt_row_num & 0x3;
    while (rowCnt)
    {
        int32_t sum = *pBias++;
        pA = in_vec;
        colCnt = size;

        //init
        NDS_VEC_VMV_S_X(NDS_VEC_V26, sum);
        //clear v4~v5
        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);

        while (colCnt != 0)
        {
            NDS_VEC_VSETVLI_E16(vl, colCnt);
            NDS_VEC_VLB_V(NDS_VEC_V2, pA);
            NDS_VEC_VLB_V(NDS_VEC_V3, pB);
            NDS_VEC_VWMACC_VV(NDS_VEC_V4, NDS_VEC_V2, NDS_VEC_V3);
            pB += vl;
            pA += vl;
            colCnt -= vl;
        }

        NDS_VEC_VSETVLI_E32_M2(vl, size);
        NDS_VEC_VREDSUM_VS(NDS_VEC_V26, NDS_VEC_V4, NDS_VEC_V26);
        NDS_VEC_VMV_X_S(sum, NDS_VEC_V26);
        sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        *pO++ = NDS_ISA_SATS((sum >> post_rshift), 16);
        rowCnt--;
    }
#else   //vqmacc
#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
    const q7_t *pB = wt_mat;
    const q31_t *pBias = bias;
    q15_t *pO = out_vec;
