        NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V4, NDS_VEC_V0);
        NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);
        sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        *pO++ = NDS_ISA_SATS((sum >> post_rshift), 16);
        rowCnt--;
    }
#endif
#endif
#elif defined(ENA_DSP_ISA_V5)

#ifdef ENA_DSP_ISA_64 //V5 64, DX25
    uint16_t  rowCnt = wt_row_num >> 2;
    const q7_t *pB = wt_mat;
    const q7_t *pA;
    q15_t     *pO = out_vec;
    const q31_t *pBias = bias;

    while (rowCnt)
    {
        q63_t   sum_q31x2_1 = 0;
        q63_t   sum_q31x2_2 = 0;
        q63_t   sum_q31x2_3 = 0;
        q63_t   sum_q31x2_4 = 0;

        uint16_t  colCnt = size >> 3;

        pA = in_vec;

        q63_t Vec_A0, Vec_A1;
        q63_t Vec_B0, Vec_B1;
        q63_t Vec_AB, Vec_AB0, Vec_AB1, Vec_AB2, Vec_AB3;

        q63_t inM11, inM12, inM21, inM22;
        while (colCnt)
        {
            Vec_AB = *__SIMD64(pA)++;
            inM11 = *__SIMD64(pB)++;
            inM12 = *__SIMD64(pB)++;
            inM21 = *__SIMD64(pB)++;
            inM22 = *__SIMD64(pB)++;

            Vec_A0 = NDS_DSP_BPICK(inM11, inM12 << 8, 0x00ff00ff00ff00ff);
            Vec_A1 = NDS_DSP_BPICK(inM11 >> 8, inM12, 0x00ff00ff00ff00ff);
            Vec_B0 = NDS_DSP_BPICK(inM21, inM22 << 8, 0x00ff00ff00ff00ff);
            Vec_B1 = NDS_DSP_BPICK(inM21 >> 8, inM22, 0x00ff00ff00ff00ff);

            Vec_AB0 = NDS_DSP_PKBB32(Vec_B0, Vec_A0); //0,8,2,10
            Vec_AB1 = NDS_DSP_PKBB32(Vec_B1, Vec_A1); //1,9,3,11
            Vec_AB2 = NDS_DSP_PKTT32(Vec_B0, Vec_A0); //4,12,6,14
            Vec_AB3 = NDS_DSP_PKTT32(Vec_B1, Vec_A1); //5,13,7,15

            sum_q31x2_1 = NDS_DSP_SMAQA(sum_q31x2_1 , Vec_AB, Vec_AB0);
            sum_q31x2_2 = NDS_DSP_SMAQA(sum_q31x2_2, Vec_AB, Vec_AB1);
            sum_q31x2_3 = NDS_DSP_SMAQA(sum_q31x2_3, Vec_AB, Vec_AB2);
            sum_q31x2_4 = NDS_DSP_SMAQA(sum_q31x2_4, Vec_AB, Vec_AB3);

            colCnt--;
        }

        sum_q31x2_1 = PADD_S32(sum_q31x2_1);
        sum_q31x2_2 = PADD_S32(sum_q31x2_2);
        sum_q31x2_3 = PADD_S32(sum_q31x2_3);
        sum_q31x2_4 = PADD_S32(sum_q31x2_4);

        if ((size & 0x7) > 3)
        {
            q31_t Vec_A = *__SIMD32(pA)++;
            q31_t inM11 = *__SIMD32(pB)++;
            q31_t inM12 = *__SIMD32(pB)++;
            q31_t inM13 = *__SIMD32(pB)++;
            q31_t inM14 = *__SIMD32(pB)++;

            q31_t Vec_A0 = NDS_DSP_BPICK(inM11, inM13 << 8, 0x00ff00ff);
            q31_t Vec_A1 = NDS_DSP_BPICK(inM11 >> 8, inM13, 0x00ff00ff);
            q31_t Vec_A2 = NDS_DSP_BPICK(inM12, inM14 << 8, 0x00ff00ff);
            q31_t Vec_A3 = NDS_DSP_BPICK(inM12 >> 8, inM14, 0x00ff00ff);

            sum_q31x2_1 = NDS_DSP_SMAQA(sum_q31x2_1, Vec_A, Vec_A0);
            sum_q31x2_2 = NDS_DSP_SMAQA(sum_q31x2_2, Vec_A, Vec_A1);
            sum_q31x2_3 = NDS_DSP_SMAQA(sum_q31x2_3, Vec_A, Vec_A2);
            sum_q31x2_4 = NDS_DSP_SMAQA(sum_q31x2_4, Vec_A, Vec_A3);

            colCnt--;
        }

        colCnt = size & 0x3;
        while (colCnt)
        {
            q7_t    inA = *pA++;
            q7_t    inB = *pB++;
            sum_q31x2_1 += inA * inB;
            inB = *pB++;
            sum_q31x2_2 += inA * inB;
            inB = *pB++;
            sum_q31x2_3 += inA * inB;
            inB = *pB++;
            sum_q31x2_4 += inA * inB;

            colCnt--;
        }

        q31_t sum_q31_1 = sum_q31x2_1;
        q31_t sum_q31_2 = sum_q31x2_2;
        q31_t sum_q31_3 = sum_q31x2_3;
        q31_t sum_q31_4 = sum_q31x2_4;

        sum_q31_1 += *pBias++;
        sum_q31_2 += *pBias++;
        sum_q31_3 += *pBias++;
        sum_q31_4 += *pBias++;

        sum_q31_1 = (sum_q31_1 >> pre_rshift) * out_scale;
        sum_q31_2 = (sum_q31_2 >> pre_rshift) * out_scale;
        sum_q31_3 = (sum_q31_3 >> pre_rshift) * out_scale;
        sum_q31_4 = (sum_q31_4 >> pre_rshift) * out_scale;

        sum_q31_1 = NDS_DSP_SRA_U(sum_q31_1, post_rshift);
        sum_q31_2 = NDS_DSP_SRA_U(sum_q31_2, post_rshift);
        sum_q31_3 = NDS_DSP_SRA_U(sum_q31_3, post_rshift);
        sum_q31_4 = NDS_DSP_SRA_U(sum_q31_4, post_rshift);

        *pO++ = NDS_DSP_SATS(sum_q31_1, 16);
        *pO++ = NDS_DSP_SATS(sum_q31_2, 16);
        *pO++ = NDS_DSP_SATS(sum_q31_3, 16);
        *pO++ = NDS_DSP_SATS(sum_q31_4, 16);

        rowCnt--;
    }

    /* left-over part of the rows */

    rowCnt = wt_row_num & 0x3;
    while (rowCnt)
    {
        q63_t     sum_q31x2 = 0;
        uint16_t  colCnt = size >> 3;

        pA = in_vec;
        while (colCnt)
        {
            q63_t Vec_V1 = *__SIMD64(pA)++;
            q63_t Vec_V2 = *__SIMD64(pB)++;
            sum_q31x2 = NDS_DSP_SMAQA(sum_q31x2, Vec_V1, Vec_V2);
            colCnt--;
        }

        sum_q31x2 = PADD_S32(sum_q31x2);

        colCnt = size & 0x7;
        while (colCnt)
        {
            q7_t      inA = *pA++;
            q7_t      inB = *pB++;
            sum_q31x2 += inA * inB;
            colCnt--;
        }

        q31_t sum_q31 = sum_q31x2;
        sum_q31 += *pBias++;

        sum_q31 = (sum_q31 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        *pO++ = NDS_DSP_SATS((sum_q31 >> post_rshift), 16);
        rowCnt--;
    }
#else //V5 32, D25
    uint16_t  rowCnt = wt_row_num >> 2;
    const q7_t *pB = wt_mat;
    const q7_t *pA;
    q15_t     *pO = out_vec;
    const q31_t *pBias = bias;

    while (rowCnt)
    {
        q31_t     sum =  *pBias++;
        q31_t     sum2 = *pBias++;
        q31_t     sum3 = *pBias++;
        q31_t     sum4 = *pBias++;

        uint16_t  colCnt = size >> 2;

        pA = in_vec;

        q31_t slot4_A;
        q31_t slot4_B;
        q31_t inM11, inM12, inM13, inM14;
        while (colCnt)
        {
            slot4_A = *__SIMD32(pA)++;
            inM11 = *__SIMD32(pB)++;
            inM12 = *__SIMD32(pB)++;
            inM13 = *__SIMD32(pB)++;
            inM14 = *__SIMD32(pB)++;

            slot4_B = NDS_DSP_BPICK(inM11, inM13 << 8, 0x00ff00ff);
            sum = NDS_DSP_SMAQA(sum,  slot4_A, slot4_B);

            slot4_B = NDS_DSP_BPICK(inM11 >> 8, inM13, 0x00ff00ff);
            sum2 = NDS_DSP_SMAQA(sum2,  slot4_A, slot4_B);

            slot4_B = NDS_DSP_BPICK(inM12, inM14 << 8, 0x00ff00ff);
            sum3 = NDS_DSP_SMAQA(sum3,  slot4_A, slot4_B);

            slot4_B = NDS_DSP_BPICK(inM12 >>8, inM14, 0x00ff00ff);
            sum4 = NDS_DSP_SMAQA(sum4,  slot4_A, slot4_B);

            colCnt--;
        }

        colCnt = size & 0x3;
        while (colCnt)
        {
            q7_t      inA = *pA++;
            q7_t      inB = *pB++;
            sum += inA * inB;
            inB = *pB++;
            sum2 += inA * inB;
            inB = *pB++;
            sum3 += inA * inB;
            inB = *pB++;
            sum4 += inA * inB;

            colCnt--;
        }

        sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        sum2 = (sum2 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        sum3 = (sum3 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        sum4 = (sum4 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);

        *pO++ = NDS_DSP_SATS((sum >> post_rshift), 16);
        *pO++ = NDS_DSP_SATS((sum2 >> post_rshift), 16);
        *pO++ = NDS_DSP_SATS((sum3 >> post_rshift), 16);
        *pO++ = NDS_DSP_SATS((sum4 >> post_rshift), 16);

        rowCnt--;
    }

    /* left-over part of the rows */

    rowCnt = wt_row_num & 0x3;

    while (rowCnt)
    {
        q31_t     sum = *pBias++;
        uint16_t  colCnt = size >> 2;

        pA = in_vec;
        while (colCnt)
        {
            q31_t tinV1 = *__SIMD32(pA)++;
            q31_t tinV2 = *__SIMD32(pB)++;
            sum = NDS_DSP_SMAQA(sum, tinV1, tinV2);
            colCnt--;
        }

        colCnt = size & 0x3;
        while (colCnt)
        {
            q7_t      inV = *pA++;
            q7_t      inM = *pB++;
            sum += inV * inM;
            colCnt--;
        }

        sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        *pO++ = NDS_DSP_SATS((sum >> post_rshift), 16);

        rowCnt--;
    }
#endif
#elif defined(ENA_DSP_ISA)
    const q7_t *pB = wt_mat;
    q15_t     *pO = out_vec;
    const q31_t *pBias = bias;
    q15_t    *pA;
    long  rowCnt = wt_row_num >> 2;

    nn_dup_s8_s16_reordered(in_vec, in_tmp_buf, size);

    while (rowCnt)
    {
        /* init sum with bias */
        q31_t     sum =  *pBias++;
        q31_t     sum2 = *pBias++;
        q31_t     sum3 = *pBias++;
        q31_t     sum4 = *pBias++;

        uint16_t  colCnt = size >> 2;
        pA = in_tmp_buf;

        while (colCnt)
        {
            long     inM11, inM12, inM13, inM14;
            long     inV;

            inV = *__SIMD32(pA)++;
            inM11 = *__SIMD32(pB)++;
            inM12 = NDS_DSP_SUNPKD831(inM11);
            inM11 = NDS_DSP_SUNPKD820(inM11);
            sum = NDS_DSP_KMADA(sum, inM11, inV);
            sum2 = NDS_DSP_KMADA(sum2, inM12, inV);
            inM13 = *__SIMD32(pB)++;
            inM14 = NDS_DSP_SUNPKD831(inM13);
            inM13 = NDS_DSP_SUNPKD820(inM13);
            sum3 = NDS_DSP_KMADA(sum3, inM13, inV);
            sum4 = NDS_DSP_KMADA(sum4, inM14, inV);

            inV = *__SIMD32(pA)++;
            inM11 = *__SIMD32(pB)++;
            inM12 = NDS_DSP_SUNPKD831(inM11);
            inM11 = NDS_DSP_SUNPKD820(inM11);
            sum = NDS_DSP_KMADA(sum, inM11, inV);
            sum2 = NDS_DSP_KMADA(sum2, inM12, inV);
            inM13 = *__SIMD32(pB)++;
            inM14 = NDS_DSP_SUNPKD831(inM13);
            inM13 = NDS_DSP_SUNPKD820(inM13);
            sum3 = NDS_DSP_KMADA(sum3, inM13, inV);
            sum4 = NDS_DSP_KMADA(sum4, inM14, inV);

            colCnt--;
        }

        colCnt = size & 0x3;
        while (colCnt)
        {
            q15_t     inV = *pA++;
            q7_t      inM = *pB++;
            q7_t      inM2 = *pB++;
            q7_t      inM3 = *pB++;
            q7_t      inM4 = *pB++;

            sum += inV * inM;
            sum2 += inV * inM2;
            sum3 += inV * inM3;
            sum4 += inV * inM4;
            colCnt--;
        }                       /* while over colCnt */

        sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        sum2 = (sum2 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        sum3 = (sum3 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        sum4 = (sum4 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        *pO++ = (NDS_DSP_SATS((sum >> post_rshift), 16));
        *pO++ = (NDS_DSP_SATS((sum2 >> post_rshift), 16));
        *pO++ = (NDS_DSP_SATS((sum3 >> post_rshift), 16));
        *pO++ = (NDS_DSP_SATS((sum4 >> post_rshift), 16));

        /* adjust the pointers and counters */
        rowCnt--;
    }

    /* left-over part of the rows */
    rowCnt = wt_row_num & 0x3;
    while (rowCnt)
    {
        q31_t     sum = *pBias++;
        uint16_t  colCnt = size >> 2;

        pA = in_tmp_buf;

        while (colCnt)
        {
            q31_t     inV1, inV2, inM11, inM12;

            pB = (q7_t *) read_and_pad_reordered((void *)pB, &inM11, &inM12);
            inV1 = *__SIMD32(pA)++;
            sum = NDS_DSP_KMADA(sum, inV1, inM11);
            inV2 = *__SIMD32(pA)++;
            sum = NDS_DSP_KMADA(sum, inV2, inM12);
            colCnt--;
        }

        /* left-over of the vector */
        colCnt = size & 0x3;
        while (colCnt)
        {
            q15_t     inV = *pA++;
            q7_t      inM = *pB++;
            sum += inV * inM;
            colCnt--;
        }

        sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        *pO++ = (NDS_DSP_SATS((sum >> post_rshift), 16));

        rowCnt--;
    }
#else // general
    uint16_t  rowCnt = wt_row_num >> 2;
    const q7_t *pB = wt_mat;
    const q7_t *pA;
    q15_t     *pO = out_vec;
    const q31_t *pBias = bias;

    while (rowCnt)
    {
        q31_t     sum =  *pBias++;
        q31_t     sum2 = *pBias++;
        q31_t     sum3 = *pBias++;
        q31_t     sum4 = *pBias++;

        uint16_t  colCnt = size >> 2;

        pA = in_vec;

        while (colCnt)
        {
            q7_t      inA1 = *pA++;
            q7_t      inA3 = *pA++;
            q7_t      inA2 = *pA++;
            q7_t      inA4 = *pA++;

            q7_t      inB1 = *pB++;
            q7_t      inB3 = *pB++;
            q7_t      inB2 = *pB++;
            q7_t      inB4 = *pB++;

            sum += inA1 * inB1 + inA2 * inB2;
            sum2 += inA1 * inB3 + inA2 * inB4;

            inB1 = *pB++;
            inB3 = *pB++;
            inB2 = *pB++;
            inB4 = *pB++;

            sum3 += inA1 * inB1 + inA2 * inB2;
            sum4 += inA1 * inB3 + inA2 * inB4;

            inB1 = *pB++;
            inB3 = *pB++;
            inB2 = *pB++;
            inB4 = *pB++;

            sum += inA3 * inB1 + inA4 * inB2;
            sum2 += inA3 * inB3 + inA4 * inB4;

            inB1 = *pB++;
            inB3 = *pB++;
            inB2 = *pB++;
            inB4 = *pB++;

            sum3 += inA3 * inB1 + inA4 * inB2;
            sum4 += inA3 * inB3 + inA4 * inB4;

            colCnt--;
        }
        colCnt = size & 0x3;
        while (colCnt)
        {
            q7_t      inA = *pA++;
            q7_t      inB = *pB++;
            sum += inA * inB;
            inB = *pB++;
            sum2 += inA * inB;
            inB = *pB++;
            sum3 += inA * inB;
            inB = *pB++;
            sum4 += inA * inB;

            colCnt--;
        }
        sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        sum2 = (sum2 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        sum3 = (sum3 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
        sum4 = (sum4 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
#ifdef ENA_DSP_ISA
        *pO++ = NDS_DSP_SATS((sum >> post_rshift), 16);
        *pO++ = NDS_DSP_SATS((sum2 >> post_rshift), 16);
        *pO++ = NDS_DSP_SATS((sum3 >> post_rshift), 16);
        *pO++ = NDS_DSP_SATS((sum4 >> post_rshift), 16);
#else
        *pO++ = NDS_ISA_SATS((sum >> post_rshift), 16);
        *pO++ = NDS_ISA_SATS((sum2 >> post_rshift), 16);
        *pO++ = NDS_ISA_SATS((sum3 >> post_rshift), 16);
        *pO++ = NDS_ISA_SATS((sum4 >> post_rshift), 16);
#endif

        rowCnt--;
    }

    rowCnt = wt_row_num & 0x3;

    while (rowCnt)
    {
        int ip_out = *pBias++;
        int j;

        pA = in_vec;
        for (j = 0; j < size; j++)
        {
            q7_t      inA = *pA++;
            q7_t      inB = *pB++;
            ip_out += inA * inB;
        }
        ip_out = (ip_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
#ifdef ENA_DSP_ISA
        *pO++ = NDS_DSP_SATS((ip_out >> post_rshift), 16);
#else
        *pO++ = NDS_ISA_SATS((ip_out >> post_rshift), 16);
#endif

        rowCnt--;
    }
#endif
    return 0;
}

