// From riscv_nn_tanh_f32.c — Taylor for small |x|, exp-based for large |x|
// Fast path: x * (1 - x^2/3)
vfloat32m4_t vfast = __riscv_vmv_v_v_f32m4(vin, vl);
vfloat32m4_t vx2 = __riscv_vfmul(vin, vin, vl);
vfloat32m4_t vx_c = __riscv_vfmul(vin, cst_1_3, vl);
vfast = __riscv_vfnmsac(vfast, vx2, vx_c, vl);              // x - x^3/3

// Full path: (exp(2x) - 1) / (exp(2x) + 1)  [computed above as vfull]

// Select: |x| >= threshold uses full path, else fast path
vfloat32m4_t vabs = __riscv_vfsgnjx(vin, vin, vl);          // fabs via sign injection
vbool8_t mask = __riscv_vmfge(vabs, threshold, vl);
vfloat32m4_t result = __riscv_vmerge_vvm_f32m4(vfast, vfull, mask, vl);
```

**T10. Fast reciprocal** (when `ENA_FAST_ALGO` is defined)
```c
// ~7-bit precision, ~3x faster than vfdiv
#ifdef ENA_FAST_ALGO
    vden = __riscv_vfrec7(vden, vl);
    vresult = __riscv_vfmul(vnum, vden, vl);
#else
    vresult = __riscv_vfdiv(vnum, vden, vl);
#endif
```

**T11. Three-pass softmax reduction**
```c
// From riscv_nn_softmax_f32.c
// Pass 1: find max via vfredmax
vfloat32m8_t vMax = __riscv_vle32_v_f32m8(in, vl);
while (remaining > 0) {
    vfloat32m8_t vTmp = __riscv_vle32_v_f32m8(ptr, vl);
    vMax = __riscv_vfmax(vMax, vTmp, vl);
}
vfloat32m1_t vMax_s = __riscv_vfredmax_tu(init, vMax, init, size);
float max = __riscv_vfmv_f(vMax_s);

// Pass 2: exp(x - max) + accumulate sum (m4 for register space during exp)
vfloat32m4_t vSum = __riscv_vfmv_v_f_f32m4(0.f, size);
while (remaining > 0) {
    vl = __riscv_vsetvl_e32m4(remaining);
    vfloat32m4_t v = __riscv_vle32_v_f32m4(in, vl);
    v = __riscv_vfsub(v, max, vl);
    // ... exp_f32(v) -> vexp ...
    __riscv_vse32(out, vexp, vl);
    vSum = __riscv_vfadd(vSum, vexp, vl);
}
vfloat32m1_t vSum_s = __riscv_vfredusum_tu(zero, vSum, zero, size);
float sum = __riscv_vfmv_f(vSum_s);

// Pass 3: divide by sum (m8 for throughput)
while (remaining > 0) {
    vl = __riscv_vsetvl_e32m8(remaining);
    vfloat32m8_t v = __riscv_vle32_v_f32m8(out, vl);
    v = __riscv_vfdiv(v, sum, vl);  // or vfrec7+vfmul if ENA_FAST_ALGO
    __riscv_vse32(out, v, vl);
}
```

**T12. Input replication for FC** (feed 4 parallel row dot-products)
```c
// nn_dup_s8_x4_reordered() duplicates input 4x with interleaving
// so vqmacc can process 4 weight rows simultaneously
nn_dup_s8_x4_reordered(in_vec, (q7_t*)in_tmp_buf, size);
```

**T13. Weight contribution precompute** (asymmetric quantization)
```c
// Precompute sum(weights) * input_offset once, add to each output
// Uses vd4dots with ones-vector for efficient summation
```

**T14. ACE custom exp** (hardware-accelerated when available)
```c
#if defined(ENA_ACE_RVV)
    ace_exp(NDS_VEC_V0, NDS_VEC_V0);  // single instruction exp
#else
    // Software polynomial exp (T8 above)
#endif
```

### Data Movement Techniques

**T15. 64-byte address alignment**
```c
ptr = (type*)nn_align((uintptr_t)ptr, 64);
```

**T16. Data type promotion chain** (for quantized ops)
```c
// From riscv_nn_ew_mul_s8_asym.c
// s8 -> s32 via sign extension
vint8m1_t v_s8 = __riscv_vle8_v_i8m1(in, vl);
vl = __riscv_vsetvl_e32m4(avl);
vint32m4_t v_s32 = __riscv_vsext_vf4(v_s8, vl);

// s32 -> s64 for requantization multiply (no overflow)
vint64m8_t product_64 = __riscv_vwmul(product_32, scale, vl);

// s64 -> s32 via narrowing shift
vint32m4_t result_32 = __riscv_vnsra(product_64, shift, vl);

// s32 -> s16 -> s8 via narrowing (with rounding mode)
vint32m4_t rounded = __riscv_vssra(result_32, 1, __RISCV_VXRM_RNU, vl);
vl = __riscv_vsetvl_e16m2(vl);
vint16m2_t r16 = __riscv_vnsra(rounded_32, 0, vl);
vl = __riscv_vsetvl_e8m1(vl);
vint8m1_t r8 = __riscv_vnsra(r16, 0, vl);
```

**T17. Masked accumulator reduction** (for multi-output FC)
```c
// From riscv_nn_fc_s8_s16_s8_sym_bias_fast.c
// After vqmacc accumulates 4 interleaved rows into one register group,
// use masked vredsum to extract each row's sum separately
vint32m1_t sum1 = __riscv_vredsum(mask1, vAcc, bias1_vec, vl);
vint32m1_t sum2 = __riscv_vredsum(mask2, vAcc, bias2_vec, vl);
vint32m1_t sum3 = __riscv_vredsum(mask3, vAcc, bias3_vec, vl);
vint32m1_t sum4 = __riscv_vredsum(mask4, vAcc, bias4_vec, vl);
// Combine via vslideup into single vector for batch processing
sum1 = __riscv_vslideup(sum1, sum2, 1, 4);
sum1 = __riscv_vslideup(sum1, sum3, 2, 4);
sum1 = __riscv_vslideup(sum1, sum4, 3, 4);
```

### Quantization-Specific

**T18. Vector saturating narrowing** (deterministic output quantization)
```c
// vnclip with rounding mode for output quantization
vint16m2_t v16 = __riscv_vnclip(v32, shift, __RISCV_VXRM_RNU, vl);
```

**T19. Vector min/max clipping** (activation clamping, replaces branches)
```c
vSum = __riscv_vmax(vSum, act_min, vl);
vSum = __riscv_vmin(vSum, act_max, vl);
```

### RVV Version Patterns

**T20. Preprocessor guard structure** (required for all RVV code)
```c
#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
    // RVV 1.0 with C intrinsics (preferred for new code)
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
    // RVV 1.0 with inline assembly macros
#elif defined(ENA_VEC_ISA)
    // RVV 0.8 fallback
#elif defined(ENA_DSP_ISA)
    // DSP path
#else
    // Plain C
#endif
```

**T21. Tail-undisturbed policy** (default in libnn)
```c
// Most intrinsics use _tu suffix for tail-undisturbed
vAcc = __riscv_vqmacc_vv_i32m8_tu(vAcc, vA, vB, vl);
vA = __riscv_vfmacc_tu(vA, coeff, vm, vl);
```

## Step 4: Evaluate Search Space for Improvements

When optimizing a function, evaluate these opportunities:

### Algorithmic
1. **Winograd convolution** — For 3x3 convs, reduces multiplies by ~2.25x
2. **Im2col + GEMM fusion** — More aggressive fusion of rearrangement with tiled computation
3. **Fewer polynomial coefficients** — Some activations may tolerate 4-6 instead of 8 (measure accuracy)
4. **vfrec7 + Newton-Raphson** — One NR iteration after vfrec7 gives ~14-bit precision at ~60% vfdiv cost:
   ```c
   vfloat32m4_t r = __riscv_vfrec7(x, vl);
   r = __riscv_vfnmsub(r, x, two, vl);  // r = r * (2 - x*r)
   ```

### Micro-architectural
5. **Software pipelining** — Overlap load[i+1] / compute[i] / store[i-1]
6. **LMUL tuning** — m8 uses all 32 regs; m4 with better scheduling might reduce spills
7. **Prefetch hints** — `__builtin_prefetch` for memory-bound ops on large tensors
8. **Segmented loads** — `vlseg2/3/4` for interleaved multi-channel data
9. **Tail-agnostic policy** — Switching from `_tu` to `_ta` may let hardware skip zeroing
10. **Indexed/strided loads** — `vlse`/`vluxei` for non-contiguous access (dilated conv)
11. **Vector register grouping** — Explore mixed LMUL within a function

### Missing Vectorizations
12. **Functions still plain-C only** — Check `Source/UtilFunctions/` for NMS, top-k, argmax
13. **F16 coverage** — Some f16 functions may lack RVV paths
14. **Grouped convolution** — May not have full RVV for all group sizes

## Step 5: Write the RVV Code

### Code Structure Template

```c
int32_t riscv_nn_<function>(/* params */)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
    // === RVV 1.0 intrinsic path (write this first) ===
    long avl = size;
    long vl;
    while (avl > 0) {
        vl = __riscv_vsetvl_e<SEW>m<LMUL>(avl);
        // ... vector operations ...
        avl -= vl;
    }
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
    // === RVV 1.0 macro path ===
    long vl;
    while (size > 0) {
        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E<SEW>, NDS_VEC_VTYPE_LMUL_M<LMUL>);
        // ... NDS_VEC_* macro operations ...
        size -= vl;
    }
#elif defined(ENA_VEC_ISA)
    // === RVV 0.8 path (optional, use macros from internal_vec_isa_v0_8.h) ===
#elif defined(ENA_DSP_ISA)
    // ... existing DSP path ...
#else
    // ... existing plain C path ...
#endif
    return 0;
}
```

### Naming Conventions for Variables
- `vl` — current vector length from vsetvl
- `avl` / `size2` — application vector length (remaining elements)
- `vIn_*` — loaded input vectors
- `vAcc_*` / `vSum_*` — accumulators
- `vResult_*` — final result before store
- `maxvl_perf_vg` — maximum VL for the chosen LMUL

### Critical Rules
1. **Always include `#include "internal_nn_math.h"`** — it pulls in all needed headers
2. **Use `_tu` (tail-undisturbed)** suffix on accumulator operations
3. **Cast vl to `long`** not `int` — matches existing code convention
4. **Handle size=0** — the while loop naturally handles this
5. **Match the plain-C output exactly** — use golden test data to verify
6. **Guard FPU ops** — floating point RVV needs both `ENA_VEC_ISA` and `ENA_VEC_FPU`
7. **Guard ACE ops** — `ENA_ACE_RVV` for Andes Customization Engine extensions

